INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_2698efe6', '1.0', 'ws_spec0001', 'POST /edges/{edge_id}/traverse и«ӢжұӮй«”', 'POST /edges/{edge_id}/traverse Request Body', 'factual', 'markdown', 'и«ӢжұӮй«”еҢ…еҗ«дёҖеҖӢ `actor_id` (дҫӢеҰӮ `usr_abc123` жҲ– `apikey_abc123`) д»ҘеҸҠдёҖеҖӢеҸҜйҒёзҡ„ `note` ж¬„дҪҚгҖӮ', 'The request body includes an `actor_id` (e.g., `usr_abc123` or `apikey_abc123`) and an optional `note` field.', '{api,request-body,traversal}', 'public', 'system', '2026-04-24 11:25:40.220298+00', NULL, '8da827ee692a2b067d6b98da026c3001d951a76bece032cb35ba88cef2a09dda', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_w002', '1.0', 'ws_spec0001', 'жң¬ең°й–Ӣзҷјз’°еўғе•ҹеӢ•', 'Local Development Stack Setup', 'procedural', 'markdown', '## еүҚзҪ®йңҖжұӮ
- Node.js 20 LTS+
- Python **3.11+**
- Docker DesktopпјҲе•ҹеӢ• PostgreSQL 17 + pgvectorпјү

## е•ҹеӢ•й–Ӣзҷјз’°еўғ
```bash
# 1. иӨҮиЈҪз’°еўғиЁӯе®ҡ
cp .env.example .env  # еЎ«е…Ҙ POSTGRES_PASSWORD иҲҮ SECRET_KEY

# 2. е®үиЈқ Node зӣёдҫқ
npm install

# 3. е®үиЈқ Python зӣёдҫқ
cd packages/api && python -m venv venv
source venv/bin/activate  # macOS/Linux
pip install -r requirements.txt && cd ../..

# 4. е•ҹеӢ•иіҮж–ҷеә«пјҲйҰ–ж¬ЎиҮӘеӢ•еҹ·иЎҢжүҖжңү schema/sql/*.sqlпјү
docker compose up -d

# 5. е•ҹеӢ• API
cd packages/api && uvicorn main:app --reload --port 8000

# 6. е•ҹеӢ• UIпјҲеҸҰдёҖеҖӢзөӮз«Ҝж©ҹпјү
cd packages/ui && npm run dev
```

APIпјҡhttp://localhost:8000 / UIпјҡhttp://localhost:5173', '## Prerequisites
- Node.js 20 LTS+
- Python **3.11+**
- Docker Desktop (runs PostgreSQL 17 + pgvector)

## Start the Dev Environment
```bash
# 1. Copy env config
cp .env.example .env  # fill in POSTGRES_PASSWORD and SECRET_KEY

# 2. Install Node dependencies
npm install

# 3. Install Python dependencies
cd packages/api && python -m venv venv
source venv/bin/activate
pip install -r requirements.txt && cd ../..

# 4. Start the database (auto-applies all schema/sql/*.sql on first run)
docker compose up -d

# 5. Start the API
cd packages/api && uvicorn main:app --reload --port 8000

# 6. Start the UI (separate terminal)
cd packages/ui && npm run dev
```

API: http://localhost:8000 / UI: http://localhost:5173', '{dev,setup,database,procedural}', 'public', 'system', '2026-04-28 00:00:00+00', NULL, '', 'human', NULL, NULL, NULL, NULL, 0.900, 0.950, 1.000, 0.900, 0.900, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_d003', '1.0', 'ws_spec0001', 'Content TypeпјҡзҜҖй»һзҡ„зҹҘиӯҳжҖ§иіӘ', 'Content Type: the nature of knowledge in a node', 'factual', 'markdown', 'жҜҸеҖӢ Memory Node еҝ…й ҲжЁҷиЁҳдёҖзЁ® Content Typeпјҡ

| Type | иӘӘжҳҺ | дҫӢеӯҗ |
|------|------|------|
| `factual` | йҷіиҝ°жҖ§дәӢеҜҰ | гҖҢpgvector ж”ҜжҸҙ cosine similarityгҖҚ |
| `procedural` | жӯҘй©ҹжөҒзЁӢ | гҖҢеҰӮдҪ•иЁӯе®ҡ Docker Compose й–Ӣзҷјз’°еўғгҖҚ |
| `preference` | еҒҸеҘҪжҲ–жұәзӯ– | гҖҢжҲ‘еҖ‘йҒёж“Ү bcrypt иҖҢйқһ argon2гҖҚ |
| `context` | иғҢжҷҜи„ҲзөЎ | гҖҢйҖҷеҖӢе°ҲжЎҲжҺЎз”ЁйӣҷиӘһиЁӯиЁҲзҡ„еҺҹеӣ гҖҚ |
| `source_document` | ж”қе…ҘжҷӮдҝқз•ҷзҡ„еҺҹе§Ӣж–Үд»¶пјҲВ§20пјү| дёҖеҖӢжңғиӯ°йҢ„йҹійҖҗеӯ—зЁҝгҖҒдёҖд»Ҫ PDF е…Ёж–Ү |

**`source_document` зү№жҖ§**пјҡз”ұ `ingest` жөҒзЁӢиҮӘеӢ•е»әз«ӢпјҢbody зӮәж–Үд»¶е…Ёж–ҮжҲ–йҖҗеӯ—зЁҝпјҢй җиЁӯеҫһ Graph View / жҗңе°Ӣ / Q&A context дёӯ**жҺ’йҷӨ**гҖӮиҗғеҸ–еҮәзҡ„зҜҖй»һйҖҸйҒҺ `source_doc_node_id` + `source_paragraph_ref` еҸҚеҗ‘йҖЈзөҗеҲ°еҺҹе§Ӣж®өиҗҪгҖӮ

Content Type еҪұйҹҝпјҡжҗңе°ӢйҒҺжҝҫгҖҒAI иҗғеҸ–еҲҶйЎһгҖҒй җиЁӯ decay half-lifeпјҲephemeral е·ҘдҪңеҚҖпјүгҖҒExport Scope й…Қе°ҚпјҲ`procedural` вҶ’ user-manualпјҢ`factual` вҶ’ functional-spec зӯүпјүгҖӮ', 'Every Memory Node must be tagged with a Content Type:

| Type | Description | Example |
|------|-------------|---------|
| `factual` | Declarative facts | "pgvector supports cosine similarity" |
| `procedural` | Step-by-step process | "How to set up a Docker Compose dev environment" |
| `preference` | Preferences or decisions | "We chose bcrypt over argon2" |
| `context` | Background context | "Why this project uses bilingual design" |
| `source_document` | Original document retained at ingestion (В§20) | A meeting transcript, a full PDF |

**`source_document` characteristics**: Created automatically by the `ingest` flow; body holds the full text or transcript. **Excluded by default** from Graph View / search / Q&A context. Extracted nodes link back to the original passage via `source_doc_node_id` + `source_paragraph_ref`.

Content Type affects: search filtering, AI extraction classification, default decay half-life (ephemeral workspaces), and Export Scope matching (`procedural` вҶ’ user-manual, `factual` вҶ’ functional-spec, etc.).', '{data-model,schema,content-type,source-document}', 'public', 'memtrace-spec', '2026-04-11 00:00:00+00', NULL, 'f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.900, 0.900, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_25ad6564', '1.0', 'ws_spec0001', 'еҖӢдәәе·ҘдҪңеҚҖеҸҜиҰӢжҖ§', 'Private Workspace Visibility', 'factual', 'markdown', 'гҖҢз§ҒжңүгҖҚ(private) е·ҘдҪңеҚҖе°ҚжүҖжңүе…¶д»–дҪҝз”ЁиҖ…е®Ңе…Ёйҡұи—ҸгҖӮ', 'A `private` workspace is completely hidden from all other users.', '{workspace-type,visibility,private}', 'public', 'system', '2026-04-24 11:25:39.649243+00', NULL, 'd9e0ea13c43e0e843f62e0fde909343ab684ea90f2dd3e4d953aaf5dbb099de5', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_i004', '1.0', 'ws_spec0001', 'еӯҳеҸ–жҺ§еҲ¶иҲҮж¬Ҡйҷҗи§’иүІпјҡviewer / contributor / admin', 'Access control and permission roles: viewer / contributor / admin', 'factual', 'plain', 'MemTrace жҺЎз”ЁйЎһ git зҡ„дёүеұӨж¬ҠйҷҗжЁЎеһӢпјҢйҒ©з”Ёж–јдәәйЎһдҪҝз”ЁиҖ…иҲҮ AI е·Ҙе…·пјҲеҗ« MCPпјүгҖӮ

и§’иүІе®ҡзҫ©пјҡ
- viewerпјҡе”Ҝи®Җ + е•Ҹзӯ” + зҜҖй»һи©•еҲҶпјҲrateпјү
- contributorпјҡviewer е…ЁйғЁиғҪеҠӣ + жҸҗеҮәдҝ®ж”№е»әиӯ°пјҲвҶ’ review queueпјҢйңҖз®ЎзҗҶе“ЎеҜ©ж ёпјү
- adminпјҡcontributor е…ЁйғЁиғҪеҠӣ + зӣҙжҺҘеҜ«е…Ҙ + еҜ©ж ёжҸҗжЎҲ + з®ЎзҗҶжҲҗе“Ў + йӮҖи«ӢдҪҝз”ЁиҖ… + и»ҹеҲӘйҷӨ/йӮ„еҺҹе·ҘдҪңеҚҖ

е·ҘдҪңеҚҖж“ҒжңүиҖ…пјҲownerпјүж°ёйҒ жҳҜ adminпјҢдёҚеҸҜйҷҚзҙҡгҖӮ

API Key scope е°ҚжҮүпјҡ
- kb:read вҶ’ viewer
- kb:propose вҶ’ contributor
- kb:write вҶ’ admin

MCP е·Ҙе…·йҒөе®ҲзӣёеҗҢиҰҸеүҮпјҡkb:read key з„Ўжі•е‘јеҸ« create_nodeпјӣkb:propose key еҸҜе‘јеҸ« propose_nodeпјӣkb:write key еҸҜзӣҙжҺҘеҜ«е…ҘгҖӮ

Contributor жҸҗжЎҲжөҒзЁӢпјҡPOST /workspaces/{ws_id}/proposals вҶ’ review_queueпјҲsource_type = contributor_proposalпјүвҶ’ admin еҜ©ж ёеҫҢз”ҹж•ҲгҖӮ

еҠ е…Ҙе·ҘдҪңеҚҖзҡ„й җиЁӯи§’иүІпјҡ
- е»әз«Ӣе·ҘдҪңеҚҖ вҶ’ adminпјҲж“ҒжңүиҖ…пјү
- йҖҸйҒҺйӮҖи«ӢйҖЈзөҗеҠ е…Ҙ вҶ’ йӮҖи«Ӣе»әз«ӢжҷӮжҢҮе®ҡзҡ„и§’иүІ
- и·Ёеә«иӨҮиЈҪзҜҖй»һ вҶ’ дёҚжҺҲдәҲд»»дҪ•жҲҗе“ЎиіҮж ј', 'MemTrace uses a git-inspired three-tier permission model that applies equally to human users and AI tools (including MCP).

Roles:
- viewer: read-only + Q&A chat + node rating (votes_up/down)
- contributor: all viewer capabilities + submit change proposals (вҶ’ review queue, requires admin approval)
- admin: all contributor capabilities + direct write + approve/reject proposals + manage members + invite users + soft-delete/restore workspace

The workspace owner is always admin and cannot be demoted.

API Key scope mapping:
- kb:read вҶ’ viewer
- kb:propose вҶ’ contributor
- kb:write вҶ’ admin

MCP tools respect the same rules: a kb:read key cannot call create_node; a kb:propose key can call propose_node; a kb:write key can write directly.

Contributor proposal flow: POST /workspaces/{ws_id}/proposals вҶ’ review_queue (source_type = contributor_proposal) вҶ’ takes effect after admin approval.

Default role on join:
- Create workspace вҶ’ admin (owner)
- Accept invite link вҶ’ role embedded in the invite token by admin
- Cross-workspace node copy вҶ’ no membership granted', '{access-control,permissions,roles,viewer,contributor,admin,mcp,api-key}', 'public', 'system', '2026-04-12 00:00:00+00', NULL, 'd1e2f3a4b5c6d1e2f3a4b5c6d1e2f3a4b5c6d1e2f3a4b5c6d1e2f3a4b5c6d1e2', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.950, 0.900, 0, 0, 0, 5, 2, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_0d6a7214', '1.0', 'ws_spec0001', 'е·ҘдҪңеҚҖеӯҳеҸ–жҺҲж¬Ҡ', 'Workspace Access Granting', 'factual', 'markdown', 'е·ҘдҪңеҚҖзҡ„еӯҳеҸ–ж¬Ҡйҷҗеғ…йҖҸйҒҺз®ЎзҗҶе“Ўзҡ„жҳҺзўәйӮҖи«ӢжҺҲдәҲгҖӮ', 'Access to a workspace is granted only via explicit admin invitation.', '{access-control,admin,invitation}', 'public', 'system', '2026-04-24 11:25:39.592594+00', NULL, '7565ff5c348962f12749977db91aa8c4ec162aaa28a3d45be254023066708312', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_k003', '1.0', 'ws_spec0001', 'зҜҖй»һи·Ёеә«иӨҮиЈҪпјҡеҸҜж”ңжҖ§', 'Cross-workspace node copy: portability', 'procedural', 'plain', 'д»»дҪ•зҜҖй»һеҸҜиў«иӨҮиЈҪеҲ°еҸҰдёҖеҖӢзҹҘиӯҳеә«пјҢдҪҶ Edge дёҚйҡЁиЎҢгҖӮиӨҮиЈҪиЎҢзӮәпјҡзӣ®жЁҷеә«дёӯеҸ–еҫ—ж–° idпјӣcreated_at йҮҚиЁӯзӮәиӨҮиЈҪжҷӮй–“пјӣprovenance.copied_from иЁҳйҢ„ { node_id, workspace_id } дҫӣжәҜжәҗпјӣзӣ®жЁҷеә«дёӯ visibility й җиЁӯзӮә privateпјӣTrust еҲҶж•ёд»Ҙеҝ«з…§её¶е…ҘпјҢе…©йӮҠеҫҢзәҢдә’дёҚеҪұйҹҝпјӣsignature еңЁзӣ®жЁҷеә«з’°еўғйҮҚж–°иЁҲз®—гҖӮCLI жҢҮд»Өпјҡmemtrace copy-node <node-id> --to <workspace-id>гҖӮAPIпјҡPOST /workspaces/{ws_id}/nodesпјҲеё¶ copied_from еҸғж•ёпјүгҖӮ', 'Any node can be copied to another Knowledge Base, but its Edges are not copied. Copy behaviour: the target KB assigns a new id; created_at is reset to the copy time; provenance.copied_from records { node_id, workspace_id } for traceability; visibility defaults to private in the target KB; Trust scores are carried as a snapshot вҖ” subsequent changes in either KB do not affect the other; signature is recomputed in the target KB context. CLI: memtrace copy-node <node-id> --to <workspace-id>. API: POST /workspaces/{ws_id}/nodes (with copied_from parameter).', '{knowledge-base,portability,copy,provenance}', 'public', 'memtrace-spec', '2026-04-11 00:00:00+00', NULL, 'c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.900, 0.900, 0, 0, 0, 1, 1, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
