INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_9d2bb35f', '1.0', 'ws_spec0001', 'API йҮ‘й‘°зҜ„еңҚиҲҮе·Ҙе…·иЎҢзӮә', 'API Key Scopes and Tool Behavior', 'factual', 'markdown', 'дёҖеҖӢ API йҮ‘й‘°еҸҜд»ҘжҢҒжңүйҖҷдёүзЁ®зҜ„еңҚдёӯзҡ„жҒ°еҘҪдёҖзЁ®гҖӮMCP е·Ҙе…·йҒөеҫӘйҮ‘й‘°зҡ„зҜ„еңҚпјҢиЎҢзӮәиҲҮзӣёеҗҢи§’иүІзҡ„зңҹдәәдҪҝз”ЁиҖ…е®Ңе…ЁдёҖиҮҙпјӣдҫӢеҰӮпјҢ`kb:read` йҮ‘й‘°дёҚиғҪиӘҝз”Ё `create_node`пјҢиҖҢ `kb:write` йҮ‘й‘°еҸҜд»ҘзӣҙжҺҘиӘҝз”Ё `create_node`гҖӮ', 'An API key can hold exactly one of these three scopes. MCP tools respect the key''s scope identically to a human user of the same role; for example, a `kb:read` key cannot call `create_node`, while a `kb:write` key can call `create_node` directly.', '{api-key,scope,restriction,tool-integration}', 'public', 'system', '2026-04-24 11:25:40.662171+00', NULL, 'ebf39bff13bb90908583ff5cb051532e6a089703a636a2ef60cb0edc2de260b1', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
