INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_a4bdc8a9', '1.0', 'ws_spec0001', 'еҫһжӯёжӘ”йӮ„еҺҹзҜҖй»һ API', 'Restore Node from Archive API', 'procedural', 'markdown', 'жҸҗдҫӣдёҖеҖӢ API з«Ҝй»һ `POST /nodes/{id}/restore`пјҢе…ҒиЁұз·ЁијҜиҖ…жҲ–жӣҙй«ҳж¬Ҡйҷҗзҡ„дҪҝз”ЁиҖ…еҫһжӯёжӘ”дёӯйӮ„еҺҹзҜҖй»һгҖӮ', 'Provide an API endpoint `POST /nodes/{id}/restore` allowing editors or higher-privileged users to restore nodes from archive.', '{api,node-archiving}', 'public', 'system', '2026-04-25 02:38:45.09492+00', NULL, '029e98ddd550f5a3e9de0fffe6caf0393b841248c6f5db9ba68f07f14c5c8c28', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_a002', '1.0', 'ws_spec0001', 'ж–Үд»¶ж”қе…ҘиҲҮ AI зҜҖй»һиҗғеҸ–', 'Document ingestion and AI node extraction', 'procedural', 'markdown', 'ж”ҜжҸҙж јејҸпјҡ`.md`гҖҒ`.txt`гҖҒ`.pdf`гҖҒ`.docx`гҖӮиҗғеҸ–жөҒзЁӢпјҡ

1. AI дҫқж–Үд»¶зөҗж§ӢпјҲжЁҷйЎҢгҖҒж®өиҗҪпјүеҲҮеүІжҲҗеҖҷйҒёеЎҠ
2. еҗ„еЎҠиў«еҲҶйЎһзӮә Content Type
3. з”ҹжҲҗйӣҷиӘһжЁҷйЎҢиҲҮе…§ж–ҮиҚүзЁҝ
4. жҸҗиӯ°еҖҷйҒё EdgeпјҲдҫқиӘһж„Ҹзӣёиҝ‘иҲҮж–Үд»¶й ҶеәҸпјү

жүҖжңүзөҗжһңйҖІе…Ҙ **Review Queue**пјҢдёҚиҮӘеӢ• commitгҖӮиҗғеҸ–зҜҖй»һзҡ„ source_type й җиЁӯзӮә `ai_generated`пјҢдәәе·Ҙз„Ўдҝ®ж”№жҺҘеҸ— вҶ’ `ai_verified`пјҢдәәе·Ҙдҝ®ж”№еҫҢжҺҘеҸ— вҶ’ `human`гҖӮжҜҸеҖӢзҜҖй»һиЁҳйҢ„ source_document иҲҮ extraction_modelгҖӮ', 'Supported formats: `.md`, `.txt`, `.pdf`, `.docx`. Extraction flow:

1. AI segments the document into candidate chunks by structure (headings, paragraphs)
2. Each chunk is classified into a Content Type
3. Bilingual title and body drafts are generated
4. Candidate Edges are proposed based on semantic proximity and document order

All results enter the **Review Queue** вҖ” never auto-committed. Extracted node source_type defaults to `ai_generated`; accepted without edits вҶ’ `ai_verified`; accepted after edits вҶ’ `human`. Each node records source_document and extraction_model.', '{ai,ingestion,extraction,document}', 'public', 'memtrace-spec', '2026-04-11 00:00:00+00', NULL, 'e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.950, 0.900, 0, 0, 0, 2, 1, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
