INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_da5739b0', '1.0', 'ws_spec0001', 'еҢҜе…Ҙй җиҰҪз•«йқўжҰӮиҰҪ', 'Import Preview Screen Overview', 'factual', 'markdown', 'еҢҜе…Ҙй җиҰҪз•«йқўйЎҜзӨәеҢҜе…ҘдҪңжҘӯзҡ„ж‘ҳиҰҒпјҢеҢ…жӢ¬зҜҖй»һе’ҢйӮҠзҡ„зёҪж•ёпјҢд»ҘеҸҠе“ӘдәӣзҜҖй»һжҳҜд№ҫж·Ёзҡ„жҲ–еҸҜиғҪжҳҜйҮҚиӨҮзҡ„гҖӮ', 'The import preview screen displays a summary of the import job, including the total number of nodes and edges, and which nodes are clean or potentially duplicates.', '{import,ui,preview}', 'public', 'system', '2026-04-24 11:25:40.950895+00', NULL, '33e0e380ea727d436286ac1bf2851417357f1fbec9cdf77e3c99a89c6c790c2a', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_1b0a6c77', '1.0', 'ws_spec0001', 'API йҮ‘й‘°/е°Қи«ҮеҒңж¬Ҡй–ҫеҖј', 'API Key/Session Suspension Threshold', 'factual', 'markdown', 'еҰӮжһңиө°иЁӘзҺҮеңЁ 10 еҲҶйҗҳе…§и¶…йҒҺ 2000 ж¬Ўи«ӢжұӮпјҢAPI йҮ‘й‘°жҲ–е°Қи«Үе°Үиў«еҒңж¬ҠгҖӮ', 'An API key or session is suspended if the traversal rate exceeds 2000 requests within a 10-minute period.', '{api-key,session,security,rate-limiting,threshold}', 'public', 'system', '2026-04-24 11:31:27.743224+00', NULL, 'b44ed89375ac73f6c55e71e4e97b9521aa00be67b37609a04552c515ac852362', 'ai', NULL, NULL, NULL, NULL, 0.593, 0.800, 1.000, 0.010, 0.500, 0, 0, 0, 1, 1, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_99877db7', '1.0', 'ws_spec0001', 'з®ЎзҗҶе“Ўи§’иүІиғҪеҠӣи©іжғ…', 'Admin Role Capabilities Detail', 'factual', 'markdown', 'з®ЎзҗҶе“Ўж“ҒжңүжүҖжңүиІўзҚ»иҖ…иғҪеҠӣпјҢдёҰеҸҜд»ҘзӣҙжҺҘеҜ«е…ҘзҜҖй»һе’ҢйӮҠпјҢз№һйҒҺеҜ©ж ёйҡҠеҲ—гҖӮд»–еҖ‘еҸҜд»Ҙжү№еҮҶжҲ–жӢ’зө•иІўзҚ»иҖ…зҡ„жҸҗжЎҲгҖҒжӣҙж”№жҲҗе“Ўи§’иүІгҖҒз§»йҷӨжҲҗе“ЎгҖҒеүөе»әйӮҖи«ӢйҖЈзөҗгҖҒе•ҹеӢ•е·ҘдҪңеҚҖи»ҹеҲӘйҷӨд»ҘеҸҠеҸ–ж¶Ҳеҫ…иҷ•зҗҶзҡ„еҲӘйҷӨгҖӮ', 'Admins have all contributor capabilities and can directly write to nodes and edges, bypassing the review queue. They can approve or reject contributor proposals, change member roles, remove members, create invite links, initiate workspace soft-deletion, and cancel pending deletions.', '{role,admin,capabilities,direct-write,member-management,workspace-lifecycle}', 'public', 'system', '2026-04-24 11:25:40.578811+00', NULL, '9595d963ebb096bb9babefc681a5b117abc51207b0587a462f1d2f5a847fb7f3', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_fee2f20e', '1.0', 'ws_spec0001', 'AI и®ҖеҸ–ж¬Ҡйҷҗпјҡй—ңиҒҜзҡ„е·ҘдҪңеҚҖ', 'AI Read Permission: Associated Workspaces', 'factual', 'markdown', 'AI еҸҜд»Ҙеҫһй—ңиҒҜзҡ„е·ҘдҪңеҚҖи®ҖеҸ–е…§е®№пјҢдҪҶдёҚиў«е…ҒиЁұеҗ‘е…¶жҸҗиӯ°еҜ«е…Ҙж“ҚдҪңгҖӮ', 'AI may read from associated workspaces but is not permitted to propose writes to them.', '{}', 'public', 'system', '2026-04-24 11:25:40.71846+00', NULL, 'bf0b60327f5653184e709699864ee935ead4af7a24ab35a084ed82d36c9699b5', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_e3e6a8a4', '1.0', 'ws_spec0001', 'UI е…Ҙй–ҖжөҒзЁӢйҖІеәҰжўқ', 'UI Onboarding Flow Progress Bar', 'factual', 'markdown', 'еңЁжҜҸеҖӢжӯҘй©ҹзҡ„й ӮйғЁйғҪжңғйЎҜзӨәдёҖеҖӢжҢҒд№…зҡ„йҖІеәҰжўқпјҢдҫӢеҰӮгҖҢжӯҘй©ҹ X / YгҖҚгҖӮеҝ…еЎ«жӯҘй©ҹжңғиў«жЁҷиЁҳпјҢеҸҜи·ійҒҺзҡ„жӯҘй©ҹеүҮйЎҜзӨәгҖҢжҡ«жҷӮи·ійҒҺгҖҚйҖЈзөҗгҖӮ', 'A persistent progress bar, e.g., "Step X of Y", is shown at the top of each step. Required steps are marked, and skippable steps show a "Skip for now" link.', '{ui,onboarding,progress}', 'public', 'system', '2026-04-24 11:31:27.668692+00', NULL, 'b765919fa3c8d7ca9d84e73220b483af69ddf3e5317b220e195ca32f868b427d', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
