INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_156804b8', '1.0', 'ws_spec0001', 'API йҮ‘й‘°ж¬ҠйҷҗзҜ„еңҚпјҡkb:write', 'API Key Scope: kb:write', 'factual', 'markdown', '`kb:write` ж¬ҠйҷҗзҜ„еңҚзҡ„ API йҮ‘й‘°жҺҲдәҲз®ЎзҗҶе“Ўи§’иүІиғҪеҠӣпјҢжҸҗдҫӣе®Ңе…ЁеҜ«е…Ҙж¬ҠйҷҗгҖӮ', 'An API key with the `kb:write` scope grants admin role capabilities, providing full write access.', '{api-key,scope,admin,write-access}', 'public', 'system', '2026-04-24 11:25:40.640994+00', NULL, '956a647920f96b7a1b1d0aff71ff87d58dc65179427575b5a85f87acd1dacaa3', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_fcfc3360', '1.0', 'ws_spec0001', 'AI е‘јеҸ«ж—ҘиӘҢиҰҒжұӮ', 'AI Call Logging Requirement', 'factual', 'markdown', 'жүҖжңү AI е‘јеҸ«пјҢз„Ўи«–жҳҜдҪҝз”Ёе·ҘдҪңеҚҖзҙҡеҲҘйӮ„жҳҜеёіжҲ¶зҙҡеҲҘзҡ„йҮ‘й‘°пјҢйғҪеҝ…й ҲиЁҳйҢ„гҖӮж—ҘиӘҢдҪңзӮәиЁҲиІ»гҖҒиӘҝи©Ұе’Ңж”ҝзӯ–еҹ·иЎҢзҡ„ж¬ҠеЁҒиЁҳйҢ„гҖӮ', 'All AI calls, regardless of whether they use a workspace-level or account-level key, must be logged. The log serves as the authoritative record for billing, debugging, and policy enforcement.', '{ai,иӘӘжҳҺ,иЁҳйҢ„,йҢҜиӘӨ,зөҗж§Ӣ}', 'public', 'system', '2026-04-24 11:25:40.870968+00', NULL, 'd602c01a63a9d7c9de1f73258fc8a94b375dadb29578da5d267ed59f356eb6fa', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_ce00334f', '1.0', 'ws_spec0001', 'MemTrace е№іеҸ°жҰӮиҰҪ', 'MemTrace Platform Overview', 'factual', 'markdown', 'MemTrace жҳҜдёҖеҖӢй–Ӣж”ҫе№іеҸ°пјҢж—ЁеңЁйҖҸйҒҺжңҖе°ҸгҖҒйҖЈжҺҘиүҜеҘҪзҡ„иЁҳжҶ¶зҜҖй»һпјҲMemory Nodesпјүж§Ӣе»әе…ұдә«зҹҘиӯҳгҖӮе…¶ж ёеҝғиЁӯиЁҲзӣ®жЁҷжҳҜи®“д»»дҪ•дәәйЎһжҲ– AI д»ЈзҗҶйғҪиғҪйҖҡйҒҺжңҖзҹӯи·Ҝеҫ‘еңЁе°ҸеһӢгҖҒеҲҶеһӢй—ңдҝӮең–дёӯжүҫеҲ°зӯ”жЎҲпјҢиҖҢдёҚжҳҜй–ұи®ҖеӨ§йҮҸж–ҮжӘ”гҖӮ', 'MemTrace is an open platform designed for building shared knowledge through minimal, well-connected Memory Nodes. Its core design goal is to allow any human or AI agent to reach any answer by following the shortest possible path through a graph of small, typed relationships вҖ” rather than reading through large documents.', '{memtrace,жҰӮиҰҪ,д»Ӣзҙ№,е№іеҸ°}', 'public', 'system', '2026-04-24 11:26:52.690912+00', NULL, '7c0dc21b5b1a8849d7704332f76000351e9532b56aad2bbacdb5d7e28acbbb42', 'ai', NULL, NULL, NULL, NULL, 0.593, 0.800, 1.000, 0.010, 0.500, 0, 0, 0, 1, 1, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_107440f8', '1.0', 'ws_spec0001', 'з°ЎеҢ–ең–иӯңијүиҚ·дёӯзҡ„зҜҖй»һ ID', 'Node IDs in Stripped Graph Payload', 'factual', 'markdown', 'з°ЎеҢ–ең–иӯңијүиҚ·дёӯзҡ„зңҹеҜҰ `memory_node.id` еҖјиў«жӣҝжҸӣзӮәдёҚйҖҸжҳҺзҡ„й ҶеәҸй җиҰҪ ID (`node_preview_N`)пјҢйҖҷдәӣ ID еңЁдёҚеҗҢи«ӢжұӮд№Ӣй–“жҳҜдёҚз©©е®ҡзҡ„гҖӮ', 'Real `memory_node.id` values in the stripped graph payload are replaced with opaque sequential preview IDs (`node_preview_N`) that are not stable across requests.', '{зҜҖй»һID,з°ЎеҢ–зөҗж§Ӣ,иіҮж–ҷијүиҚ·}', 'public', 'system', '2026-04-24 11:25:39.758281+00', NULL, '1deb02df329cb170fcdc2a70609066f0765abe86315b577b6bdf3c214b6cb7e7', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_e7f9e165', '1.0', 'ws_spec0001', 'зҜҖй»һеүөе»әжҷӮзҡ„й җиЁӯеҖј', 'Default Values on Node Creation', 'factual', 'markdown', 'ж–°зҜҖй»һеүөе»әзҡ„й җиЁӯеҖјеҢ…жӢ¬ `content.format` зӮә `"plain"`, `trust.score` зӮә 0.5, `trust.dimensions` (accuracy 0.5, freshness 1.0, utility 0.5, author_rep 0.5), д»ҘеҸҠ `trust.votes` (up 0, down 0, verifications 0)гҖӮ', 'Default values for new node creation include `content.format` as `"plain"`, `trust.score` as 0.5, `trust.dimensions` (accuracy 0.5, freshness 1.0, utility 0.5, author_rep 0.5), and `trust.votes` (up 0, down 0, verifications 0).', '{иЁӯе®ҡ,й җиЁӯеҖј}', 'public', 'system', '2026-04-24 11:25:39.907406+00', NULL, '11dce764ed34376c489501afe7fa9330e9e93e1b549033f0c531a25cf39e346c', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_9fbbb5eb', '1.0', 'ws_spec0001', 'Memory Node v1 жүӢеӢ•з·ЁијҜзҡ„ж–°еўһж¬„дҪҚ', 'Additional Fields for Manual Editing in Memory Node v1', 'factual', 'markdown', 'зӮәдәҶж”ҜжҢҒжүӢеӢ•еүөе»әе’Ңз·ЁијҜпјҢ`content.format` е’Ң `provenance.updated_at` ж¬„дҪҚиў«йҷ„еҠ еҲ° `node.v1.json`гҖӮ', 'To support manual creation and editing, `content.format` and `provenance.updated_at` fields are appended to `node.v1.json`.', '{schema,з·ЁијҜ,ж¬„дҪҚ}', 'public', 'system', '2026-04-24 11:25:39.850666+00', NULL, '452abb112c53437818f068b051dae5b3ed9838e84f1596251e5802d0afdf7c11', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_a9dee7ad', '1.0', 'ws_spec0001', 'AI з·ЁијҜйҷҗеҲ¶пјҡеғ…йҷҗз•¶еүҚе·ҘдҪңеҚҖзҜҖй»һ', 'AIиқәеҲ»ж‘©?о“ҺпҚ—еҡ—о«Іоһ°?пҡ—жҘөйӣҝо°Ә?иқӯВҖжҡә?AI Edit Restriction: Current Workspace Nodes', 'factual', 'markdown', 'з•¶ allow_edits: true жҷӮпјҢAI еҸӘиғҪе°Қз•¶еүҚе·ҘдҪңеҚҖдёӯзҡ„зҜҖй»һжҸҗеҮәз·ЁијҜе»әиӯ°гҖӮ', '??`allow_edits: true` ?оҝў?AI?иҠҫпҒҚж’ пҡҷоһ°?пҡ—жҘөйӣҝо°Ә?йҠқеү”?иқӯВҖжҡәоөҘ??з®ҮжҘҠй ӣиҮ¬йҒЈйң…е•ңВҖ?When `allow_edits: true`, AI may only propose edits to nodes within the current workspace.', '{}', 'public', 'system', '2026-04-24 11:25:40.697058+00', NULL, 'e7bf10d2741911fda9174cec1c320fb1aa084b441af68b4ccf38eb16825802f4', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_d1d90285', '1.0', 'ws_spec0001', 'API Key ж¬ҠйҷҗзҜ„еңҚпјҡkb:propose', 'API Key Scope: kb:propose', 'factual', 'markdown', 'е…·жңү kb:propose ж¬ҠйҷҗзҜ„еңҚзҡ„ API Key жҺҲдәҲиІўзҚ»иҖ…пјҲcontributorпјүи§’иүІзҡ„иғҪеҠӣпјҢеҢ…жӢ¬жүҖжңүи®ҖеҸ–ж¬Ҡйҷҗд»ҘеҸҠжҸҗдәӨе»әиӯ°зҡ„иғҪеҠӣгҖӮ', '`kb:propose` иқӯп„’???API ?о•Ҝо”¶?пҺ…?йһҺпј№пҷӯ?пҶІ??и„°пҒҚ?о®—??пҶ°п”Ө?ВҖ?пҗҰ??оЎҝиҝӮ?иҲҖ??п—»?йҲӯж–—?йң…е•Ғ??иіў???An API key with the `kb:propose` scope grants contributor role capabilities, including all read access and the ability to submit proposals.', '{api-key,scope,contributor,proposal}', 'public', 'system', '2026-04-24 11:25:40.620555+00', NULL, '676665976061e64f48291d081a2edea8a4ae9b7eafef376b42fd6438a6a74965', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_565d7142', '1.0', 'ws_spec0001', 'иЁҳжҶ¶зҜҖй»һж–°еўһдҫҶжәҗж–Үд»¶еҸғиҖғж¬„дҪҚ', 'й–®оҰ·пҲқж“ғоқ„?жҡәоөҘоЎҮжҶ“оөҘ??пӢЁиҫЈж’ҳоҹЎоң…??Memory Nodes Add Source Document Reference Columns', 'factual', 'markdown', 'зӮәдәҶе°ҮиҗғеҸ–зҜҖй»һйҖЈзөҗеҲ°е…¶дҫҶжәҗж®өиҗҪпјҢmemory_nodes иЎЁдёӯж–°еўһдәҶ source_doc_node_idпјҲеј•з”ЁдҫҶжәҗж–Үд»¶зҜҖй»һ IDпјүе’Ң source_paragraph_refпјҲж®өиҗҪзҙҡеҸғиҖғпјүж¬„дҪҚгҖӮ', '?з®”?ж’ пӢӘ??оЎҫ?иқӯВҖжҡәоө§??е—Ҷ?з•ҫиҸ”о’Ұ?о°ӯој…йҹҸз‘ҡ?еҡ—п–—memory_nodes` йҠөе…¶и‘ү?е•Ј?йҲӯ?`source_doc_node_id` (ж’ҳоҹЎоң…зҡһо“Ҹ?йҡһе—Ҙ?жҡәоіӘD) ??`source_paragraph_ref` (з•ҫиҸ”о’Ұиққо«°пҚҶж’ҳоҹЎоң…) ?оӨ—ВҖ?To link extracted nodes to their source passages, `source_doc_node_id` (referencing the source document node ID) and `source_paragraph_ref` (paragraph-level reference) columns are added to the `memory_nodes` table.', '{дҫҶжәҗ,ж–Үд»¶}', 'public', 'system', '2026-04-24 11:25:40.793451+00', NULL, '4e72999ffec0aa27b1841c5dbbc5838c1ee5228b0c418ba246b5513acf930071', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_w003', '1.0', 'ws_spec0001', 'Spec KB еҲқе§ӢеҢ–иӘӘжҳҺ', 'Spec KB Initialization', 'procedural', 'markdown', '## Spec KB жҳҜеҰӮдҪ•е»әз«Ӣзҡ„пјҹ
иҰҸж јзҹҘиӯҳеә«пјҲ`ws_spec0001`пјүз”ұ `schema/sql/099_seed_spec_kb.sql` иҮӘеӢ•е»әз«ӢгҖӮ

`docker compose up` жҷӮпјҢPostgreSQL init ж©ҹеҲ¶дҫқеәҸеҹ·иЎҢ `schema/sql/` дёӢжүҖжңү `*.sql`пјҢ`099_seed_spec_kb.sql` жңҖеҫҢеҹ·иЎҢпјҢе»әз«Ӣе·ҘдҪңеҚҖгҖҒеҜ«е…Ҙ 30 еҖӢзҜҖй»һиҲҮе°ҚжҮүйӮҠгҖӮ

## й©—иӯү
```bash
docker exec -it memtrace-db psql -U memtrace -d memtrace \n  -c "SELECT COUNT(*) FROM memory_nodes WHERE workspace_id=''ws_spec0001'' AND status=''active'';" 
# й җжңҹпјҡ30
```

## йҮҚзҪ® Spec KB
```bash
docker compose down -v && docker compose up -d
```', '## How is the Spec KB created?
The Spec Knowledge Base (`ws_spec0001`) is created automatically by `schema/sql/099_seed_spec_kb.sql`.

When you run `docker compose up`, PostgreSQL''s init mechanism executes all `*.sql` files under `schema/sql/` in order. `099_seed_spec_kb.sql` runs last, creating the workspace and inserting 30 nodes and their edges.

## Verify
```bash
docker exec -it memtrace-db psql -U memtrace -d memtrace \n  -c "SELECT COUNT(*) FROM memory_nodes WHERE workspace_id=''ws_spec0001'' AND status=''active'';" 
# Expected: 30
```

## Reset Spec KB
```bash
docker compose down -v && docker compose up -d
```', '{dev,seed,procedural}', 'public', 'system', '2026-04-28 00:00:00+00', NULL, '', 'human', NULL, NULL, NULL, NULL, 0.900, 0.950, 1.000, 0.900, 0.900, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_d692bb11', '1.0', 'ws_spec0001', 'README/дҪҝз”Ёж–Үд»¶жӣҙж–°пјҡеӨҡеә«гҖҒе·ІзҹҘ ID дҪҝз”Ёжғ…еўғ', 'README/Usage Document Update: Multiple Workspaces, Known ID Scenario', 'procedural', 'markdown', 'README е’ҢдҪҝз”Ёж–Үд»¶е·Іжӣҙж–°пјҢиӘӘжҳҺеӨҡеә«гҖҒе·ІзҹҘ ID дҪҝз”Ёжғ…еўғпјҡе°Ү `MEMTRACE_WS` иЁӯе®ҡзӮәжңҖеёёз”Ёе·ҘдҪңеҚҖпјҢдёҰеңЁжҹҘи©ўе…¶д»–е·ҘдҪңеҚҖжҷӮпјҢжҜҸж¬Ўе‘јеҸ«е·Ҙе…·йғҪеё¶дёҠ `workspace_id` еҸғж•ёгҖӮ', 'The README and usage documentation have been updated to describe the multiple workspaces, known ID scenario: set `MEMTRACE_WS` to the most frequently used workspace, and when querying other workspaces, include the `workspace_id` parameter with each tool call.', '{ж–Үд»¶,дҪҝз”Ёжғ…еўғ,е·ҘдҪңеҚҖ}', 'public', 'system', '2026-04-26 00:29:47.118808+00', NULL, '9ac19666134fbb8959c26d7cb4f2bb7a4d735773f634d8f3c72e31d1df271051', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_d001', '1.0', 'ws_spec0001', 'Memory NodeпјҡзҹҘиӯҳзҡ„жңҖе°Ҹе–®дҪҚ', 'Memory Node: the atomic unit of knowledge', 'factual', 'markdown', 'Memory Node жҳҜ MemTrace дёӯзҹҘиӯҳзҡ„жңҖе°Ҹе–®дҪҚгҖӮжҜҸеҖӢзҜҖй»һжҚ•жҚү**дёҖеҖӢ**жғіжі•пјҢеҢ…еҗ«пјҡ

- **йӣҷиӘһжЁҷйЎҢиҲҮе…§ж–Ү**пјҲzh-TW + enпјүпјҢеҗ„иҮӘзҚЁз«Ӣ
- **Content Type**пјҡ`factual` / `procedural` / `preference` / `context` / `source_document`
- **Format**пјҡ`plain` жҲ– `markdown`
- **Tags**пјҡеӯ—дёІйҷЈеҲ—пјҢз”Ёж–јеҲҶйЎһиҲҮжҗңе°Ӣ
- **Visibility**пјҡ`public` / `team` / `private`
- **Provenance**пјҡдҪңиҖ…гҖҒе»әз«ӢжҷӮй–“гҖҒSHA-256 з°Ҫз« гҖҒsource_type
- **Trust**пјҡеӣӣз¶ӯеәҰдҝЎд»»еҲҶж•ё
- **Traversal**пјҡиө°иЁӘиЁҲж•ёиҲҮдёҚйҮҚиӨҮиЁӘе®ўж•ё
- **Status**пјҡ`active` / `archived`пјҲarchived еҫһй җиЁӯиҰ–ең–йҡұи—ҸпјҢдёҚеҲӘйҷӨпјү

**дёҰиЎҢеҜ«е…Ҙзӣёй—ңж¬„дҪҚ**пјҲВ§17пјүпјҡ
- `version` вҖ” жЁӮи§ҖйҺ–ж•ҙж•ёпјҢжҜҸж¬Ў UPDATE иҮӘеӢ• +1пјӣPATCH еҝ…й Ҳеё¶ `X-Node-Version` header
- `conflict_status` вҖ” `flagged` / `resolved`пјҢз”ұиЎқзӘҒжӘўжё¬еҜ«е…Ҙ
- `conflict_detail` вҖ” JSONBпјҢиЁҳйҢ„иЎқзӘҒйЎһеһӢиҲҮзӣёй—ңзҜҖй»һ

**дҫҶжәҗж–Үд»¶иҝҪжәҜж¬„дҪҚ**пјҲВ§20пјүпјҡ
- `source_doc_node_id` вҖ” жҢҮеҗ‘ `source_document` йЎһеһӢзҜҖй»һпјҢз”Ёж–јиҝҪжәҜиҗғеҸ–дҫҶжәҗ
- `source_paragraph_ref` вҖ” еӯ—дёІпјҢжЁҷиЁҳеңЁеҺҹж–Үд»¶дёӯзҡ„ж®өиҗҪдҪҚзҪ®пјҲеҰӮ `page:3, para:2` жҲ– `00:14:32-00:15:01`пјү

зҜҖй»һ ID ж јејҸпјҡ`mem_<hex8>`пјҢдҫӢеҰӮ `mem_a1b2c3d4`гҖӮ', 'A Memory Node is the atomic unit of knowledge in MemTrace. Each node captures **one** idea and contains:

- **Bilingual title + body** (zh-TW + en), independently authored
- **Content Type**: `factual` / `procedural` / `preference` / `context` / `source_document`
- **Format**: `plain` or `markdown`
- **Tags**: string array for classification and search
- **Visibility**: `public` / `team` / `private`
- **Provenance**: author, creation timestamp, SHA-256 signature, source_type
- **Trust**: four-dimension trust score
- **Traversal**: visit count and unique visitor count
- **Status**: `active` / `archived` (archived nodes are hidden from default views, not deleted)

**Concurrency fields** (В§17):
- `version` вҖ” optimistic-lock integer, auto-incremented on every UPDATE; PATCH must include `X-Node-Version` header
- `conflict_status` вҖ” `flagged` / `resolved`, set by the conflict detection job
- `conflict_detail` вҖ” JSONB, records conflict type and related node

**Source-document traceability fields** (В§20):
- `source_doc_node_id` вҖ” references a `source_document`-type node for extraction traceability
- `source_paragraph_ref` вҖ” string marking the original location (e.g. `page:3, para:2` or `00:14:32-00:15:01`)

Node ID format: `mem_<hex8>`, e.g. `mem_a1b2c3d4`.', '{data-model,schema,core,version,conflict}', 'public', 'memtrace-spec', '2026-04-11 00:00:00+00', NULL, 'd4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.950, 0.900, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_playbook_001', '1.0', 'ws_spec0001', 'MemTrace PlaybookпјҡзҹҘиӯҳең–иӯңеҺҹеүҮ', 'MemTrace Playbook: Principles of Knowledge Mapping', 'context', 'markdown', '### ж ёеҝғеҺҹеүҮ
1. **еҺҹеӯҗжҖ§**пјҡжҜҸеҖӢзҜҖй»һжҮүзІҫзўәжҸҸиҝ°дёҖеҖӢзҚЁз«Ӣзҡ„жҰӮеҝөгҖӮ
2. **йӣҷиӘһе°ҚзЁұ**пјҡжҸҗдҫӣиӢұж–Үе’Ңдёӯж–Үе…§е®№пјҢд»Ҙзўәдҝқи·ЁиӘһиЁҖзҷјзҸҫгҖӮ
3. **й—ңдҝӮе„Әе…Ҳ**пјҡжІ’жңүйӮҠзҡ„зҜҖй»һжҳҜеӯӨз«Ӣзҡ„иЁҳжҶ¶гҖӮе§ӢзөӮиҖғж…®е®ғеҰӮдҪ•иҲҮзҸҫжңүзҹҘиӯҳзӣёй—ңиҒҜгҖӮ', '### Core Principles
1. **Atomicity**: Each node should describe exactly one independent concept.
2. **Bilingual Symmetry**: Provide both English and Chinese content to ensure cross-lingual discovery.
3. **Relationship First**: A node without edges is isolated memory. Always consider how it relates to existing knowledge.', '{playbook,philosophy,core}', 'public', 'system', '2026-04-24 13:35:31.814382+00', NULL, 'manual_playbook_001', 'ai', NULL, NULL, NULL, NULL, 0.500, 0.500, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
