INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_1b50a9b1', '1.0', 'ws_spec0001', 'иЁҳжҶ¶зҜҖй»һз·ЁијҜеҷЁж¬„дҪҚ', 'Memory Node Editor Fields', 'factual', 'markdown', 'ж’ұз®Ү?/иқәеҲ»ж‘©йҠөе…ёоЎ…?ж№§оҜ·йҲӯпүҢ??п•һ?йӣҝпҡ–?йӣҝиј»оң…?пҶҜвҖөж’–жҖ’ВҖ?The creation/edit form exposes several fields for user input.', 'ж’ұз®Ү?/иқәеҲ»ж‘©йҠөе…ёоЎ…?ж№§оҜ·йҲӯпүҢ??п•һ?йӣҝпҡ–?йӣҝиј»оң…?пҶҜвҖөж’–жҖ’ВҖ?The creation/edit form exposes several fields for user input.', '{editor,fields,memory-node}', 'public', 'system', '2026-04-24 11:25:39.497376+00', NULL, 'b20effdba67a36c189fcc02d6a494aa870056bd4e8a4f6b878040a55275100d1', 'ai', NULL, NULL, NULL, NULL, 0.593, 0.800, 1.000, 0.010, 0.500, 0, 0, 0, 1, 1, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_w001', '1.0', 'ws_spec0001', 'е°ҲжЎҲеҘ—д»¶зөҗж§Ӣ', 'Project Package Structure', 'factual', 'markdown', 'MemTrace жҺЎз”Ё npm workspaces monorepoпјҢж №зӣ®йҢ„ `package.json` з®ЎзҗҶе…ӯеҖӢеҘ—д»¶пјҡ

| еҘ—д»¶ | и·Ҝеҫ‘ | иӘһиЁҖ | и§’иүІ |
|------|------|------|------|
| core | packages/core | TypeScript | е…ұз”ЁеһӢеҲҘгҖҒdecay иЁҲз®—гҖҒID/з°Ҫз« з”ўз”ҹеҷЁ |
| api | packages/api | Python/FastAPI | REST APIгҖҒиіҮж–ҷеә«еӯҳеҸ–гҖҒAI жҠҪиұЎеұӨ |
| ui | packages/ui | React/Vite | з¶Ій ҒеүҚз«Ҝ |
| cli | packages/cli | TypeScript | жң¬ең° CLI е·Ҙе…· |
| mcp | packages/mcp | TypeScript | MCP serverпјҲstdio + SSE еӮіијёпјү |
| ingest | packages/ingest | TypeScript | ж–Үд»¶ж”қе…Ҙ pipeline |

`core` з”ұ `cli` еј•з”Ёпјӣ`api` зҚЁз«Ӣж–ј TS еҘ—д»¶д№ӢеӨ–гҖӮ', 'MemTrace uses an npm workspaces monorepo. The root `package.json` manages six packages:

| Package | Path | Language | Role |
|---------|------|----------|------|
| core | packages/core | TypeScript | Shared types, decay logic, ID/signature generator |
| api | packages/api | Python/FastAPI | REST API, database access, AI abstraction layer |
| ui | packages/ui | React/Vite | Web frontend |
| cli | packages/cli | TypeScript | Local CLI tool |
| mcp | packages/mcp | TypeScript | MCP server (stdio + SSE transports) |
| ingest | packages/ingest | TypeScript | Document ingestion pipeline |

`core` is consumed by `cli`. `api` is independent of the TS workspace.', '{dev,architecture,monorepo}', 'public', 'system', '2026-04-28 00:00:00+00', NULL, '', 'human', NULL, NULL, NULL, NULL, 0.900, 0.950, 1.000, 0.900, 0.900, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
