INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_76037494', '1.0', 'ws_spec0001', 'жүӢеӢ•еүөе»әиҲҮз·ЁијҜиЁҳжҶ¶зҜҖй»һ', 'Manual Memory Node Creation & Editing', 'procedural', 'markdown', 'дҪҝз”ЁиҖ…еҸҜд»ҘйҖҸйҒҺ UI дёӯе°Ҳз”Ёзҡ„з·ЁијҜйқўжқҝжүӢеӢ•еүөе»әе’Ңз·ЁијҜиЁҳжҶ¶зҜҖй»һгҖӮ', 'Users can manually create and edit Memory Nodes through a dedicated editor panel within the UI.', '{memory-node,creation,editing,ui}', 'public', 'system', '2026-04-24 11:25:39.311534+00', NULL, 'e1d24b6e7c1be1933fca1f5c438ed6deae3ddb38f9887c720feb6bd537e5e981', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_bd6996dd', '1.0', 'ws_spec0001', 'иЁҳжҶ¶зҜҖй»һе…§е®№ијёе…ҘжЁЎејҸ', 'Memory Node Content Input Modes', 'factual', 'markdown', 'жҜҸеҖӢиЁҳжҶ¶зҜҖй»һзҡ„жӯЈж–Ү (`content.body`) ж”ҜжҢҒе…©зЁ®ијёе…ҘжЁЎејҸгҖӮ', 'Each Memory Node body (`content.body`) supports two input modes.', '{memory-node,content,input}', 'public', 'system', '2026-04-24 11:25:39.354196+00', NULL, '0d9fdbf1ccbc62f8451c6a16bd834ea4e2ef14bebea32091c6e3fb59657e02f4', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_g003', '1.0', 'ws_spec0001', 'Edge й—ңдҝӮйЎһеһӢпјҡеӣӣзЁ®иӘһж„Ҹж–№еҗ‘', 'Edge relation types: four semantic directions', 'factual', 'markdown', '| Relation | иӘһж„Ҹ | дҪҝз”ЁжҷӮж©ҹ |
|----------|------|----------|
| `depends_on` | дҫҶжәҗзҜҖй»һзҡ„жҲҗз«Ӣдҫқиіҙзӣ®жЁҷзҜҖй»һ | A зҡ„жөҒзЁӢеүҚжҸҗжҳҜ B зҡ„жҰӮеҝө |
| `extends` | дҫҶжәҗзҜҖй»һе»¶дјёжҲ–иЈңе……зӣ®жЁҷзҜҖй»һ | A жҳҜ B зҡ„йҖІйҡҺзүҲжң¬ |
| `related_to` | жңүзӣёй—ңжҖ§дҪҶз„ЎжҳҺзўәдҫқиіҙж–№еҗ‘ | A е’Ң B йғҪеұ¬ж–јеҗҢдёҖдё»йЎҢ |
| `contradicts` | дҫҶжәҗзҜҖй»һзҡ„е…§е®№иҲҮзӣ®жЁҷзҜҖй»һзҹӣзӣҫ | A зҡ„зөҗи«–иҲҮ B зӣёиЎқзӘҒ |

йҒёж“ҮжӯЈзўәзҡ„ relation type еҫҲйҮҚиҰҒпјҢеӣ зӮәе®ғжұәе®ҡдәҶ co-access boost зҡ„еј·еәҰпјҢд»ҘеҸҠ AI agent еңЁйҒҚжӯ·ең–жҷӮеҰӮдҪ•и§Ји®Җй—ңдҝӮгҖӮ', '| Relation | Semantics | When to use |
|----------|-----------|-------------|
| `depends_on` | Source requires target to be valid | A''s process presupposes B''s concept |
| `extends` | Source extends or supplements target | A is an advanced version of B |
| `related_to` | Related without clear dependency direction | A and B belong to the same topic |
| `contradicts` | Source conflicts with target | A''s conclusion conflicts with B |

Choosing the correct relation type matters: it determines co-access boost strength and how AI agents interpret the relationship when traversing the graph.', '{graph-mechanics,relation-type,edge,schema}', 'public', 'memtrace-spec', '2026-04-11 00:00:00+00', NULL, 'f7a2b3c4d5e6f7a2b3c4d5e6f7a2b3c4d5e6f7a2b3c4d5e6f7a2b3c4d5e6f7a2', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.950, 0.900, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_g004', '1.0', 'ws_spec0001', 'Trust ScoreпјҡзҜҖй»һеҸҜдҝЎеәҰеӣӣз¶ӯи©•еҲҶ', 'Trust Score: four-dimension node credibility rating', 'factual', 'markdown', 'жҜҸеҖӢзҜҖй»һжңүдёҖеҖӢеҗҲжҲҗ `trust_score`пјҲ0вҖ“1пјүпјҢз”ұеӣӣеҖӢз¶ӯеәҰеҠ ж¬ҠиЁҲз®—пјҡ

| з¶ӯеәҰ | ж¬„дҪҚ | ж¬ҠйҮҚ | иӘӘжҳҺ |
|------|------|------|------|
| жә–зўәеәҰ | `dim_accuracy` | 40% | е…§е®№жҳҜеҗҰжӯЈзўәз„ЎиӘӨ |
| ж–°й®®еәҰ | `dim_freshness` | 25% | иіҮиЁҠжҳҜеҗҰд»ҚзӮәжңҖж–° |
| еҜҰз”ЁеәҰ | `dim_utility` | 25% | е°Қи®ҖиҖ…жҳҜеҗҰжңүеҜҰйҡӣе№«еҠ© |
| дҪңиҖ…иҒІиӯҪ | `dim_author_rep` | 10% | иІўзҚ»иҖ…зҡ„жӯ·еҸІеҸҜйқ жҖ§ |

```
trust_score = accuracyГ—0.4 + freshnessГ—0.25 + utilityГ—0.25 + author_repГ—0.1
```

## жҠ•зҘЁж©ҹеҲ¶пјҲvote_trustпјү

и©•еҲҶд»Ҙ **1вҖ“5 ж•ҙж•ё**жҸҗдәӨпјҲAPI жҺҘеҸ— accuracy иҲҮ utility е…©еҖӢз¶ӯеәҰпјүпјҢеҫҢз«ҜеҸ–жүҖжңүжҠ•зҘЁзҡ„е№іеқҮеҖјйҷӨд»Ҙ 5 жҸӣз®—зӮә 0вҖ“1 жө®й»һж•ёеҫҢжӣҙж–°зҜҖй»һгҖӮ

**API**пјҡ`POST /workspaces/{ws_id}/nodes/{node_id}/vote-trust`
```json
{ "accuracy": 4, "utility": 5 }
```

**MCP Tool**пјҡ`vote_trust(node_id, accuracy, utility)`
- AI agent еңЁи®ҖеҸ–зҜҖй»һеҫҢпјҢиӢҘиӘҚзӮәе…§е®№жӯЈзўәдё”жңүз”ЁпјҢжҮүдё»еӢ•е‘јеҸ«
- жҜҸдҪҚдҪҝз”ЁиҖ…е°ҚеҗҢдёҖзҜҖй»һеҸӘиғҪжңүдёҖзӯҶжҠ•зҘЁпјҲON CONFLICT DO UPDATEпјү
- жҠ•зҘЁиЁҳйҢ„еӯҳж–ј `node_trust_votes` иЎЁ

## confirm_node_validity

`POST /workspaces/{ws_id}/nodes/{node_id}/confirm-validity` еҸҜе°ҚзҜҖй»һйҖІиЎҢдёҖйҚөзўәиӘҚпјҡиҮӘеӢ•е°Ү `dim_accuracy` жҸҗеҚҮиҮі 1.0 дёҰйҮҚз®— `trust_score`пјҢеҗҢжҷӮжӣҙж–° `validity_confirmed_at` жҷӮй–“жҲігҖӮзӯүеҗҢж–јгҖҢжҲ‘е·Ідәәе·Ҙж ёеҜҰжӯӨзҜҖй»һд»Қз„¶жӯЈзўәгҖҚгҖӮ

## TypeScript еҜҰдҪң

`packages/core/src/trust.ts` жҸҗдҫӣ `computeTrustScore()` иҲҮ `updateTrustScore()`пјҢиҲҮ Python з«ҜиЁҲз®—зөҗжһңдёҖиҮҙпјҲиӘӨе·® < 0.01пјүгҖӮ', 'Each node carries a composite `trust_score` (0вҖ“1) computed from four weighted dimensions:

| Dimension | Field | Weight | Meaning |
|-----------|-------|--------|---------|
| Accuracy | `dim_accuracy` | 40% | Whether the content is correct |
| Freshness | `dim_freshness` | 25% | Whether the information is still current |
| Utility | `dim_utility` | 25% | Whether the content is practically helpful |
| Author Reputation | `dim_author_rep` | 10% | Historical reliability of the contributor |

```
trust_score = accuracyГ—0.4 + freshnessГ—0.25 + utilityГ—0.25 + author_repГ—0.1
```

## Voting mechanism (vote_trust)

Scores are submitted as **integers 1вҖ“5** (API accepts accuracy and utility). The backend averages all votes, divides by 5 to get a 0вҖ“1 float, then updates the node.

**API**: `POST /workspaces/{ws_id}/nodes/{node_id}/vote-trust`
```json
{ "accuracy": 4, "utility": 5 }
```

**MCP Tool**: `vote_trust(node_id, accuracy, utility)`
- AI agents should call this proactively after reading a node they find correct and useful
- Each user has one vote per node (ON CONFLICT DO UPDATE)
- Votes stored in the `node_trust_votes` table

## confirm_node_validity

`POST /workspaces/{ws_id}/nodes/{node_id}/confirm-validity` is a one-tap validity stamp: automatically raises `dim_accuracy` to 1.0, recomputes `trust_score`, and sets `validity_confirmed_at`. Equivalent to "I have manually verified this node is still accurate."

## TypeScript implementation

`packages/core/src/trust.ts` exposes `computeTrustScore()` and `updateTrustScore()`, matching the Python-side result to within 0.01.', '{graph-mechanics,trust,vote,quality,mcp-tool,credibility}', 'public', 'system', '2026-04-29 00:00:00+00', NULL, '', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.950, 0.900, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_i001', '1.0', 'ws_spec0001', 'дҪҝз”ЁиҖ…иӘҚиӯүпјҡEmail иҲҮеҜҶзўј', 'User authentication: email and password', 'procedural', 'plain', 'MemTrace жҺЎз”Ё Email + Password иӘҚиӯүи·Ҝеҫ‘гҖӮе®үе…ЁжҺӘж–ҪеҢ…жӢ¬пјҡbcrypt йӣңж№ҠпјҲcost вүҘ 12пјүгҖҒеҜҶзўјж”ҝзӯ–пјҲ8вҖ“128 еӯ—е…ғгҖҒеӨ§е°ҸеҜ«+ж•ёеӯ—гҖҒHaveIBeenPwned жҙ©жјҸжӘўжҹҘпјүгҖҒemail й©—иӯүдҝЎпјҲ24 е°ҸжҷӮж•ҲжңҹпјүгҖҒеӨұж•— 5 ж¬ЎйҺ–е®ҡ 15 еҲҶйҗҳгҖӮзҷ»е…ҘеҫҢж ёзҷј JWT SessionпјҲ7 еӨ©пјүпјҢйҖҸйҒҺ Authorization: Bearer жЁҷй ӯеӮійҒһпјҢзҷ»еҮәд»Ҙ blocklist з«ӢеҚіеӨұж•ҲгҖӮзӣ®еүҚдёҚж”ҜжҸҙз¬¬дёүж–№ OAuth зҷ»е…ҘпјҢд»Ҙз°ЎеҢ–иӘҚиӯүиЎЁйқўдёҰжёӣе°‘еӨ–йғЁдҫқиіҙгҖӮ', 'MemTrace uses Email + Password authentication. Security measures include: bcrypt hash (cost вүҘ 12), password policy (8вҖ“128 chars, upper+lower+digit, HaveIBeenPwned check), verification email (24h expiry), and 5-failure lockout for 15 minutes. Upon login, a JWT session (7 days) is issued and passed via the Authorization: Bearer header. Logout is handled via an immediate blocklist. Third-party OAuth is currently not supported to simplify the authentication surface and reduce external dependencies.', '{auth,security,jwt,password-policy}', 'public', 'memtrace-spec', '2026-04-11 00:00:00+00', NULL, 'a4b5c6d7e8f9a4b5c6d7e8f9a4b5c6d7e8f9a4b5c6d7e8f9a4b5c6d7e8f9a4b5', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.900, 0.900, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_a6a2a683', '1.0', 'ws_spec0001', 'иЁҳжҶ¶зҜҖй»һ ID', 'Memory Node ID', 'factual', 'markdown', '`memory_nodes` иЎЁдёӯзҡ„ `id` ж¬„дҪҚжҳҜдё»йҚөпјҢйЎһеһӢзӮә TEXTпјҢдҫӢеҰӮ `mem_abc123`гҖӮ', 'The `id` column in the `memory_nodes` table is the primary key, of type TEXT, e.g., `mem_abc123`.', '{database,schema,memory_nodes,column}', 'public', 'system', '2026-04-24 11:25:38.856937+00', NULL, 'b9327bb4b77a1cdb973a11d5f37e2eea745b8d5da337fc61dc0c6f2f5bcc77b7', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_d07c29a1', '1.0', 'ws_spec0001', 'жӣҙж–°жҷӮй–“ж¬„дҪҚ (provenance.updated_at)', 'Updated At Field (`provenance.updated_at`)', 'factual', 'markdown', '`provenance.updated_at`з”Ҳп„‘??п•қпҚҶ?з®Ҹ?йҠқиҺҺ??дәӨ??оҝң??жҫҶ?еҡ—пҗӯ?йҠқпҡҳоҰҖж•№пҶі??п„ң??е…ё?жҶӘп•қйҒЈиқЎп•қ?зҳҘоҗІжҙ»иқәеҲ»ж‘©?оҝңпҒҚ?пҒёиә«ж‘°о«®ВҖ?The `provenance.updated_at` field is an optional string (date-time format) that is set on every edit after initial creation.', '`provenance.updated_at`з”Ҳп„‘??п•қпҚҶ?з®Ҹ?йҠқиҺҺ??дәӨ??оҝң??жҫҶ?еҡ—пҗӯ?йҠқпҡҳоҰҖж•№пҶі??п„ң??е…ё?жҶӘп•қйҒЈиқЎп•қ?зҳҘоҗІжҙ»иқәеҲ»ж‘©?оҝңпҒҚ?пҒёиә«ж‘°о«®ВҖ?The `provenance.updated_at` field is an optional string (date-time format) that is set on every edit after initial creation.', '{}', 'public', 'system', '2026-04-24 11:25:39.88639+00', NULL, 'fde73fc348c926db7350610cbd46f6cc5b253b7227e3720fad21e1ac55261d00', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_i002', '1.0', 'ws_spec0001', 'REST API иҲҮеӨ–йғЁ API Key', 'REST API and external API keys', 'factual', 'markdown', 'еӨ–йғЁжңҚеӢҷиҲҮи…іжң¬д»Ҙ **API Key** иӘҚиӯүпјҲж јејҸпјҡ`mt_live_<hex>`пјүпјҢиҖҢйқһ session JWTгҖӮKey еҸҜз¶Ғе®ҡиҮізү№е®ҡ workspace жҲ–и·Ё workspaceпјҢе»әз«ӢеҫҢе®Ңж•ҙйҮ‘й‘°еҸӘйЎҜзӨәдёҖж¬ЎгҖӮеӣӣзЁ® scopeпјҡ

| Scope | ж¬Ҡйҷҗ |
|-------|------|
| `kb:read` | и®ҖеҸ– KBгҖҒзҜҖй»һгҖҒEdge |
| `kb:write` | е»әз«ӢиҲҮз·ЁијҜзҜҖй»һгҖҒEdge |
| `node:traverse` | иЁҳйҢ„иө°иЁӘдәӢд»¶ |
| `node:rate` | жҸҗдәӨи·Ҝеҫ‘и©•еҲҶпјҲ1вҖ“5пјү|

жүҖжңү API з«Ҝй»һеүҚз¶ҙ `/api/v1`пјҢдҪҝз”Ё `Authorization: Bearer` еӮійҒһ key жҲ– tokenпјҲдјәжңҚеҷЁдҫқеүҚз¶ҙеҚҖеҲҶпјүгҖӮ', 'External services and scripts authenticate with **API Keys** (format: `mt_live_<hex>`), not session JWTs. Keys may be scoped to a specific workspace or valid across all. Full key value shown only once at creation. Four scopes:

| Scope | Grants |
|-------|--------|
| `kb:read` | Read KBs, nodes, edges |
| `kb:write` | Create and edit nodes, edges |
| `node:traverse` | Record traversal events |
| `node:rate` | Submit path ratings (1вҖ“5) |

All API endpoints prefixed with `/api/v1`, using `Authorization: Bearer` for both keys and session tokens (server distinguishes by prefix).', '{api,api-key,access-control,integration}', 'public', 'memtrace-spec', '2026-04-11 00:00:00+00', NULL, 'b5c6d7e8f9a4b5c6d7e8f9a4b5c6d7e8f9a4b5c6d7e8f9a4b5c6d7e8f9a4b5c6', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.950, 0.900, 0, 0, 0, 2, 1, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_k001', '1.0', 'ws_spec0001', 'Knowledge BaseпјҡзҹҘиӯҳеә«пјҲWorkspaceпјү', 'Knowledge Base: the container workspace', 'factual', 'plain', 'Knowledge BaseпјҲеҸҲзЁұ WorkspaceпјүжҳҜ Memory Node иҲҮ Edge зҡ„е®№еҷЁпјҢе°ҚжҮүдёҖеҖӢзҚЁз«Ӣзҡ„зҹҘиӯҳй ҳеҹҹжҲ–е°ҲжЎҲгҖӮжҜҸеҖӢдҪҝз”ЁиҖ…еҸҜе»әз«ӢеӨҡеҖӢзҹҘиӯҳеә«гҖӮзҹҘиӯҳеә«жң¬иә«жңүе…ұдә«еұӨзҙҡпјҲpublic / restricted / privateпјүпјҢиҲҮзҜҖй»һзҡ„ visibility еҗ„иҮӘзҚЁз«ӢвҖ”вҖ”жңүж•ҲеӯҳеҸ–ж¬ҠеҸ–е…©иҖ…ијғеҡҙж јзҡ„дёҖж–№гҖӮзҹҘиӯҳеә«еҸҜд»Ҙеҫһз©әзҷҪй–Ӣе§ӢпјҢд№ҹеҸҜд»ҘеҫһдёҖд»Ҫж–Үд»¶е•ҹеӢ•дёҰз”ұ AI иҗғеҸ–зҜҖй»һгҖӮID ж јејҸпјҡws_<hex8>гҖӮ', 'A Knowledge Base (Workspace) is the container for Memory Nodes and Edges, corresponding to an independent knowledge domain or project. Users can create multiple Knowledge Bases. A Knowledge Base has its own sharing level (public / restricted / private), independent from node-level visibility вҖ” effective access is the more restrictive of the two. A Knowledge Base may be started blank or bootstrapped from a document with AI extraction. ID format: ws_<hex8>.', '{knowledge-base,workspace,container}', 'public', 'memtrace-spec', '2026-04-11 00:00:00+00', NULL, 'a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.900, 0.900, 0, 0, 0, 3, 1, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_k002', '1.0', 'ws_spec0001', 'зҹҘиӯҳеә«е…ұдә«еұӨзҙҡпјҡеӣӣзЁ®еҸҜиҰӢжҖ§', 'Knowledge Base sharing levels: four visibility tiers', 'factual', 'markdown', '| еұӨзҙҡ | иӯҳеҲҘзўј | иӘӘжҳҺ |
|------|--------|------|
| е…Ёе…¬й–Ӣ | `public` | д»»дҪ•дәәпјҲеҗ«жңӘзҷ»е…ҘпјүзҡҶеҸҜжҺўзҙўиҲҮй–ұи®Җ `public` зҜҖй»һ |
| жңүжўқд»¶е…¬й–Ӣ | `conditional_public` | д»»дҪ•дәәзҡҶеҸҜзңӢеҲ°ең–иӯңзөҗж§ӢпјҲжӢ“ж’ІпјүпјҢдҪҶзҜҖй»һе…§е®№йҡұи—ҸпјӣеҸҜеҗ‘з®ЎзҗҶе“ЎжҸҗдәӨеҠ е…Ҙз”іи«Ӣ |
| йҷҗеҲ¶е…¬й–Ӣ | `restricted` | зҹҘиӯҳеә«е°ҚйқһжҲҗе“ЎдёҚеҸҜиҰӢпјҢеҝ…й Ҳз”ұ admin жҳҺзўәйӮҖи«ӢжүҚиғҪеҠ е…Ҙ |
| з§Ғжңү | `private` | еғ…ж“ҒжңүиҖ…еҸҜиҰӢпјҢз„Ўжі•зҷјеҮәйӮҖи«Ӣ |

**йҮҚиҰҒ**пјҡvisibility еңЁе»әз«ӢжҷӮиЁӯе®ҡеҫҢ**дёҚеҸҜи®Ҡжӣҙ**пјҲimmutableпјүгҖӮд»»дҪ• `PATCH /workspaces/{ws_id}` еҗ« `visibility` ж¬„дҪҚзҡ„и«ӢжұӮдёҖеҫӢеӣһ `400 Immutable field: visibility`гҖӮе»әз«ӢжҷӮ UI еҝ…й Ҳжё…жҘҡйЎҜзӨәеӣӣеҖӢеұӨзҙҡпјҢдҪҝз”ЁиҖ…еҝ…й ҲжҳҺзўәзўәиӘҚгҖӮ

зҜҖй»һеұӨзҙҡзҡ„ visibilityпјҲpublic / team / privateпјүзҚЁз«Ӣж–јзҹҘиӯҳеә«еұӨзҙҡпјҢжңҖзөӮеӯҳеҸ–ж¬ҠеҸ–е…©иҖ…ијғеҡҙж јзҡ„дёҖж–№гҖӮ', '| Tier | Identifier | Description |
|------|------------|-------------|
| Public | `public` | Anyone (incl. unauthenticated) can discover and read `public` nodes |
| Conditional Public | `conditional_public` | Anyone can see graph topology, but node content is hidden; users may submit a join request to admins |
| Restricted | `restricted` | KB is invisible to non-members; entry requires explicit admin invitation |
| Private | `private` | Owner-only; invitations cannot be issued |

**Important**: visibility is **immutable** after creation. Any `PATCH /workspaces/{ws_id}` containing `visibility` is rejected with `400 Immutable field: visibility`. The creation UI must show all four tiers clearly with inline descriptions and require explicit user confirmation.

Node-level visibility (`public` / `team` / `private`) is independent of KB-level visibility вҖ” effective access is the more restrictive of the two.', '{knowledge-base,sharing,visibility,access-control,four-tier}', 'public', 'memtrace-spec', '2026-04-11 00:00:00+00', NULL, 'b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.950, 0.900, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_10a89b1f', '1.0', 'ws_spec0001', 'еҸ—йӮҖдҪҝз”ЁиҖ…и§’иүІеҲҶй…Қ', 'Invited User Role Assignment', 'factual', 'markdown', 'еҸ—йӮҖдҪҝз”ЁиҖ…е°Үд»ҘйӮҖи«Ӣд»ӨзүҢдёӯжҢҮе®ҡзҡ„и§’иүІж·»еҠ еҲ°е·ҘдҪңеҚҖдёӯгҖӮ', 'Invited users are added to the workspace with the role specified in the invite token.', '{roles,invitation,access-control}', 'public', 'system', '2026-04-24 11:25:39.631905+00', NULL, '7cf62b3b242f03e9b7889e041598b464fd164b5d7d1f01cba4a9eda874bbb8ed', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_79dce6e3', '1.0', 'ws_spec0001', 'иЁҳжҶ¶зҜҖй»һ Schema зүҲжң¬', 'Memory Node Schema Version', 'factual', 'markdown', '`memory_nodes` иЎЁдёӯзҡ„ `schema_version` ж¬„дҪҚйЎһеһӢзӮә TEXTпјҢеӣәе®ҡзӮә ''1.0''гҖӮ', 'The `schema_version` column in the `memory_nodes` table is of type TEXT, fixed to ''1.0''.', '{database,schema,memory_nodes,column}', 'public', 'system', '2026-04-24 11:25:38.872833+00', NULL, 'ba4fdaf3d15b468f342627140d094e4d7edd8e03d683ca2e527e33dca2be84ed', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_o001', '1.0', 'ws_spec0001', 'еҲқж¬ЎдҪҝз”Ёеј•е°ҺпјҡWeb UI зІҫйқҲ', 'First-run onboarding: web UI wizard', 'procedural', 'plain', 'йҰ–ж¬Ўзҷ»е…ҘеҫҢиҮӘеӢ•йЎҜзӨәпјҢе®ҢжҲҗеҫҢж°ёд№…дёҚеҶҚеҪҲеҮәпјҲеҸҜеҫһ Settings вҶ’ Getting Started йҮҚж–°й–Ӣе•ҹпјүгҖӮе…«жӯҘжөҒзЁӢпјҡ

в‘  е»әз«ӢеёіиҷҹпјҲEmail + Passwordпјү
в‘Ў й©—иӯү Email
в‘ў е‘ҪеҗҚз¬¬дёҖеҖӢзҹҘиӯҳеә«пјҲйӣҷиӘһеҗҚзЁұ + еҸҜиҰӢжҖ§пјҢй җиЁӯ privateпјү
в‘Ј йҒёж“ҮзҹҘиӯҳеә«йЎһеһӢпјҡEvergreenпјҲй•·ж•ҲеһӢпјҢй җиЁӯпјүжҲ– EphemeralпјҲзҹӯж•ҲеһӢпјүвҖ” **е»әз«ӢеҫҢдёҚеҸҜи®Ҡжӣҙ**
в‘Ө йҒёж“Үиө·й»һпјҡз©әзҷҪ жҲ– дёҠеӮіж–Үд»¶пјҲ.md/.txt/.pdf/.docxпјү
в‘Ҙ AI Provider иЁӯе®ҡпјҲеғ…ж–Үд»¶и·Ҝеҫ‘йЎҜзӨәпјҢеҸҜи·ійҒҺпјү
в‘Ұ Review иҗғеҸ–еҖҷйҒёзҜҖй»һпјҲиҮіе°‘жҺҘеҸ—дёҖеҖӢжүҚиғҪз№јзәҢпјү
в‘§ е®ҢжҲҗпјҲйЎҜзӨәдёүеҖӢжҚ·еҫ‘пјҡжүӢеӢ•ж–°еўһзҜҖй»һгҖҒйӮҖи«ӢжҲҗе“ЎгҖҒйҖЈжҺҘ AI е·Ҙе…·пјү

йҖІеәҰд»ҘдјәжңҚеҷЁз«Ҝзҡ„ `onboarding` зү©д»¶иҝҪи№ӨпјҲ`steps_done[]` + `steps_skipped[]`пјүпјҢдёӯж–·еҫҢеҸҜеҫһдёҠж¬ЎжңӘе®ҢжҲҗжӯҘй©ҹжҒўеҫ©гҖӮ`completed: true` еҫҢж°ёйҒ дёҚеҶҚиҮӘеӢ•йЎҜзӨәгҖӮ', 'Shown automatically on first login; permanently dismissed after completion (re-accessible from Settings вҶ’ Getting Started). Eight-step flow:

в‘  Create account (Email + Password)
в‘Ў Verify email
в‘ў Name first Knowledge Base (bilingual name + visibility, default private)
в‘Ј Choose Knowledge Base Type: Evergreen (default) or Ephemeral вҖ” **immutable after creation**
в‘Ө Choose starting point: blank or upload document (.md/.txt/.pdf/.docx)
в‘Ҙ AI provider setup (shown only on document path, skippable)
в‘Ұ Review extracted candidate nodes (at least one must be accepted to advance)
в‘§ Done (three shortcuts: add first node, invite someone, connect AI tool)

Progress tracked server-side via the `onboarding` object (`steps_done[]` + `steps_skipped[]`); resumes from the last incomplete step after interruption. Once `completed: true`, the wizard is never shown automatically again.', '{onboarding,ui,wizard,ux,kb-type}', 'public', 'memtrace-spec', '2026-04-11 00:00:00+00', NULL, 'd7e8f9a4b5c6d7e8f9a4b5c6d7e8f9a4b5c6d7e8f9a4b5c6d7e8f9a4b5c6d7e8', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.900, 0.900, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_45b2269d', '1.0', 'ws_spec0001', 'иЁҳжҶ¶зҜҖй»һдҪңиҖ…', 'Memory Node Author', 'factual', 'markdown', '`memory_nodes` иЎЁдёӯзҡ„ `author` ж¬„дҪҚйЎһеһӢзӮә TEXTпјҢеӯҳе„ІиЁҳжҶ¶зҜҖй»һзҡ„дҪңиҖ…гҖӮ', 'The `author` column in the `memory_nodes` table is of type TEXT, storing the author of the memory node.', '{database,schema,memory_nodes,column}', 'public', 'system', '2026-04-24 11:25:39.051144+00', NULL, 'a6702d11b7568adb799d43ae69e7fccd6ac9372871cf1d585ea67034809ab809', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_o002', '1.0', 'ws_spec0001', 'еҲқж¬ЎдҪҝз”Ёеј•е°ҺпјҡCLI memtrace init', 'First-run onboarding: CLI memtrace init', 'procedural', 'plain', 'еҹ·иЎҢ `memtrace init` е•ҹеӢ•зөӮз«Ҝж©ҹдә’еӢ•ејҸзІҫйқҲпјҢдә”жӯҘпјҡ

в‘  иӘҚиӯүпјҡзҷ»е…Ҙж—ўжңүеёіиҷҹ / е»әз«Ӣж–°еёіиҷҹ
в‘Ў е»әз«Ӣз¬¬дёҖеҖӢзҹҘиӯҳеә«пјҡиӢұж–ҮеҗҚзЁұ + еҸҜиҰӢжҖ§пјҲprivate / restricted / publicпјҢй җиЁӯ privateпјү
в‘ў йҒёж“Ү KB йЎһеһӢпјҡevergreenпјҲй•·ж•ҲеһӢпјҢй җиЁӯпјүжҲ– ephemeralпјҲзҹӯж•ҲеһӢпјүвҖ” **е»әз«ӢеҫҢдёҚеҸҜи®Ҡжӣҙ**
в‘Ј AI Provider иЁӯе®ҡпјҲеҸҜ Enter и·ійҒҺпјүпјҡйҒёж“Ү openai / anthropic дёҰијёе…Ҙ API KeyпјҲиҮӘеӢ•жё¬и©ҰйҖЈз·ҡпјү
в‘Ө еҢҜе…Ҙж–Үд»¶пјҲеҸҜ Enter и·ійҒҺпјүпјҡијёе…ҘжӘ”жЎҲи·Ҝеҫ‘жҲ– URL

иЁӯе®ҡеҜ«е…Ҙ `~/.memtrace/config.json`пјҢз«ӢеҚі `chmod 600`гҖӮ

йҮҚиӨҮеҹ·иЎҢпјҡи©ўе•ҸиҰҒжӣҙж–° AI provider / еҲҮжҸӣй җиЁӯе·ҘдҪңеҚҖ / йҮҚж–°иӘҚиӯү / йҖҖеҮәпјҢдёҚиҮӘеӢ•иҰҶеҜ«зҸҫжңүиЁӯе®ҡгҖӮ', 'Running `memtrace init` launches an interactive terminal wizard with five steps:

в‘  Authentication: log in to existing account / create new account
в‘Ў Create first Knowledge Base: English name + visibility (private / restricted / public, default private)
в‘ў Choose KB type: evergreen (default) or ephemeral вҖ” **immutable after creation**
в‘Ј AI provider setup (press Enter to skip): choose openai / anthropic and enter API key (auto-tests connection)
в‘Ө Import document (press Enter to skip): provide file path or URL

Config written to `~/.memtrace/config.json` with `chmod 600` immediately.

Re-running: prompts which setting to update вҖ” AI provider / switch default workspace / re-authenticate / exit. Existing values are not overwritten unless explicitly selected.', '{onboarding,cli,init,setup,kb-type}', 'public', 'memtrace-spec', '2026-04-11 00:00:00+00', NULL, 'e8f9a4b5c6d7e8f9a4b5c6d7e8f9a4b5c6d7e8f9a4b5c6d7e8f9a4b5c6d7e8f9', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.900, 0.900, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_p003', '1.0', 'ws_spec0001', 'дәәиҲҮ AI зҡ„еҚ”дҪңзҹҘиӯҳең–', 'Co-authorship between humans and AI', 'context', 'plain', 'MemTrace дёӯпјҢдәәиҲҮ AI еҜ«е…ҘеҗҢдёҖејөең–гҖӮең–зҡ„зөҗж§ӢвҖ”вҖ”Edge зҡ„ж¬ҠйҮҚгҖҒиө°иЁӘиЁҲж•ёгҖҒи©•еҲҶвҖ”вҖ”еҸҚжҳ е“ӘдәӣзҹҘиӯҳеҜҰйҡӣдёҠиў«иӯүжҳҺжңүз”ЁпјҢиҖҢйқһеҸӘжҳҜиў«иЁҳйҢ„гҖӮDecay зўәдҝқең–зҡ„иӘ еҜҰжҖ§пјҡжІ’дәәиө°зҡ„йҖЈзөҗиҮӘз„¶ж¶ҲйҖҖпјҢй »з№Ғиў«дҪҝз”Ёзҡ„йҖЈзөҗеј·еҢ–дёҰжҢҒзәҢеӯҳеңЁгҖӮжңҖзөӮеҪўжҲҗдёҖеҖӢеңҚз№һгҖҢзңҹжӯЈйҮҚиҰҒзҡ„зҹҘиӯҳгҖҚиҮӘжҲ‘зө„з№”зҡ„зҹҘиӯҳеә«гҖӮ', 'In MemTrace, humans and AI write into the same graph. The graph''s structure вҖ” edge weights, traversal counts, path ratings вҖ” reflects which knowledge has actually proven useful, not just what was recorded. Decay keeps the graph honest: connections nobody follows fade; connections visited frequently, rated positively, or extended by other nodes strengthen and persist. The result is a knowledge base that self-organises around what actually matters.', '{philosophy,core,ai,co-authorship}', 'public', 'memtrace-spec', '2026-04-11 00:00:00+00', NULL, 'c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.900, 0.900, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_2c1bd9d5', '1.0', 'ws_spec0001', 'е°Қи©ұ APIпјҡзҷјйҖҒж¶ҲжҒҜ (POST /chat)', 'Chat API: Send Message (POST /chat)', 'procedural', 'markdown', 'йҖҸйҒҺ POST и«ӢжұӮеҗ‘жҢҮе®ҡзҡ„е·ҘдҪңеҚҖзҷјйҖҒж¶ҲжҒҜгҖӮеҸҜд»ҘеӮійҒһеҸҜйҒёзҡ„ `session_id` д»Ҙз№јзәҢзҸҫжңүе°Қи©ұгҖӮ', 'Sends a message to a specified workspace via a POST request. An optional `session_id` can be passed to continue an existing conversation.', '{api,chat,message,conversation,post}', 'public', 'system', '2026-04-24 11:31:27.693915+00', NULL, '6b15654db2b55b29e7943d96ebfe8bd110b52e5febab150f4e704a1b2117ab6b', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_6d8524a7', '1.0', 'ws_spec0001', 'ж–°ж•ёж“ҡжЁЎеһӢж¬„дҪҚ', 'New Data Model Fields', 'factual', 'markdown', 'ж•ёж“ҡжЁЎеһӢдёӯж–°еўһдәҶ `version`, `conflict_status`, `conflict_detail`, `source_doc_node_id`, е’Ң `source_paragraph_ref` зӯүж¬„дҪҚгҖӮ', 'New fields `version`, `conflict_status`, `conflict_detail`, `source_doc_node_id`, and `source_paragraph_ref` have been added to the data model.', '{data-model,schema,update}', 'public', 'system', '2026-04-24 11:31:27.718604+00', NULL, 'ce86c3a5dbe8e825cb9600f783656939236cc44481125fd58c074491c61e572c', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_1fc9c6b4', '1.0', 'ws_spec0001', 'AI д»ЈзҗҶе·ҘдҪңжөҒзЁӢпјҡжҗңе°ӢзҸҫжңүзҜҖй»һ', 'AI Agent Workflow: Search Existing Nodes', 'procedural', 'markdown', 'AI д»ЈзҗҶеңЁе»әз«Ӣж–°зҜҖй»һеүҚпјҢжҮүе…Ҳе‘јеҸ« `search_nodes("иӘҚиӯүж©ҹеҲ¶")` зӯүеҠҹиғҪпјҢзўәиӘҚзҹҘиӯҳеә«дёӯжҳҜеҗҰе·ІеӯҳеңЁзӣёй—ңзҜҖй»һпјҢйҒҝе…ҚйҮҚиӨҮгҖӮ', 'Before creating a new node, an AI agent should first call `search_nodes("authentication mechanism")` or similar functions to check if related nodes already exist in the knowledge base, preventing duplication.', '{aiд»ЈзҗҶ,е·ҘдҪңжөҒзЁӢ,зҜҖй»һе»әз«Ӣ,жҗңе°Ӣ}', 'public', 'system', '2026-04-25 02:40:02.057085+00', NULL, 'ce76ce6a71d629231411b6006cde3379e98c2074b2cf40c3fc050542c9a16cfb', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_dc852972', '1.0', 'ws_spec0001', 'MEMTRACE_TOKEN е®үе…ЁжҸҗйҶ’', 'MEMTRACE_TOKEN Security Reminder', 'factual', 'markdown', 'й—ңж–ј `MEMTRACE_TOKEN` зҡ„е®үе…ЁжҸҗйҶ’ж–Үеӯ—е·ІеҠ е…ҘдјәжңҚеҷЁе•ҹеӢ•жҷӮзҡ„жЁҷжә–йҢҜиӘӨж—ҘиӘҢ (stderr log) дёӯгҖӮ', 'A security reminder text regarding `MEMTRACE_TOKEN` has been added to the server startup''s standard error log (stderr log).', '{з’°еўғи®Ҡж•ё,е®үе…ЁжҖ§,ж—ҘиӘҢ}', 'public', 'system', '2026-04-25 02:39:36.926692+00', NULL, '656f7b6e924f07b2bef8f84a0a2a011de8f9270d6618c86707eb069cb8973af7', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
