INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_42669ba9', '1.0', 'ws_spec0001', 'POST /edges/{edge_id}/rate и«ӢжұӮй«”', 'POST /edges/{edge_id}/rate Request Body', 'factual', 'markdown', 'и«ӢжұӮй«”еҢ…еҗ«дёҖеҖӢ `rating` ж¬„дҪҚпјҲ1 еҲ° 5 д№Ӣй–“зҡ„ж•ҙж•ёпјүе’ҢдёҖеҖӢеҸҜйҒёзҡ„ `note` ж¬„дҪҚгҖӮжҜҸеҖӢеҹ·иЎҢиҖ…е°ҚжҜҸжўқйӮҠеҸӘиғҪжҸҗдәӨдёҖж¬Ўи©•еҲҶпјҢеҫҢзәҢжҸҗдәӨе°ҮиҰҶи“Ӣе…ҲеүҚзҡ„и©•еҲҶгҖӮ', 'The request body includes a `rating` field (an integer between 1 and 5) and an optional `note` field. Only one rating per actor per edge is enforced, with subsequent submissions overwriting previous ratings.', '{api,request-body,rating,constraints}', 'public', 'system', '2026-04-24 11:25:40.239378+00', NULL, 'a5a308930ff1aefa0598e53a5f2529fd427006c614b29d6f873d4ac68e4b6ed4', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
