INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_d2b5ef2f', '1.0', 'ws_spec0001', 'MCP дјәжңҚеҷЁдёӯзҡ„иіҮжәҗ URI иҷ•зҗҶ', 'Resource URI Handling in MCP Server', 'factual', 'markdown', 'MCP дјәжңҚеҷЁж №ж“ҡи«ӢжұӮеҸғж•ёдёӯзҡ„ URIпјҢиҷ•зҗҶе°Қ `memtrace://guide/node` е’Ң `memtrace://guide/edge` зҡ„и«ӢжұӮпјҢдёҰеӣһеӮіе°ҚжҮүзҡ„ Markdown е…§е®№гҖӮе°Қж–јжңӘзҹҘиіҮжәҗ URIпјҢдјәжңҚеҷЁжңғжӢӢеҮәйҢҜиӘӨгҖӮ', 'The MCP server handles requests for `memtrace://guide/node` and `memtrace://guide/edge` URIs based on the request parameters, returning corresponding Markdown content. For unknown resource URIs, the server throws an error.', '{mcp,server,resource,uri,api}', 'public', 'system', '2026-04-25 02:39:28.168325+00', NULL, '2a481a49932b3fe3aaa57af8df71c64f827b6103478398eaaae36179a315ab44', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
