INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_033baf41', '1.0', 'ws_spec0001', 'NODE_GUIDE е…§е®№е®ҡзҫ©', 'NODE_GUIDE Content Definition', 'factual', 'markdown', '`NODE_GUIDE` еёёж•ёе®ҡзҫ©дәҶзҜҖй»һж¬„дҪҚиҰҸж јгҖҒ`content_type` иӘӘжҳҺгҖҒ`visibility` иӘӘжҳҺгҖҒе»әз«ӢжңҖдҪіеҜҰиёҗд»ҘеҸҠеёёиҰӢйҢҜиӘӨгҖӮ', 'The `NODE_GUIDE` constant defines node field specifications, `content_type` explanation, `visibility` explanation, best practices for creation, and common errors.', '{node_guide,node,specification,documentation}', 'public', 'system', '2026-04-25 02:39:28.703205+00', NULL, 'e455fd7e83ae5aa06dfc303f056131a6fba3450abac4370621b5128c99d786f6', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_f2edb572', '1.0', 'ws_spec0001', 'йӮҠиө°иЁӘзөұиЁҲж•ёж“ҡзөҗж§Ӣ', 'Edge Traversal Statistics Data Structure', 'factual', 'markdown', 'йӮҠйҹҝжҮүдёӯзҡ„ `traversal` зү©д»¶еҢ…еҗ« `count`пјҲиө°иЁӘж¬Ўж•ёпјүгҖҒ`rating_avg`пјҲе№іеқҮи©•еҲҶпјүе’Ң `rating_count`пјҲи©•еҲҶж¬Ўж•ёпјүж¬„дҪҚгҖӮ', 'The `traversal` object in an edge response includes `count` (number of traversals), `rating_avg` (average rating), and `rating_count` (number of ratings) fields.', '{data-structure,traversal-stats,edge,rating}', 'public', 'system', '2026-04-24 11:25:40.274389+00', NULL, '44138550101d58d53cf07a6ec12d41ed6fae6e149da9cf27f11fffac79788237', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_c8db759e', '1.0', 'ws_spec0001', 'йҖЈеҗ‘е°ҒеӯҳзҜҖй»һзҡ„йӮҠжңғиҮӘеӢ•иЎ°жёӣ', 'з”Үиұў?иқӯВҖжҡәоөҰоӯ ?о°ӯој…?п„–?йӢЎжҖҘжҘҡ??Edges Connected to Archived Nodes Are Faded', 'factual', 'markdown', 'жүҖжңүйҖЈеҗ‘е·Іе°ҒеӯҳзҜҖй»һзҡ„йӮҠпјҢе…¶еӨ–и§ҖжңғиҮӘеӢ•и®ҠзӮәгҖҢиЎ°жёӣгҖҚзӢҖж…ӢпјҢдҪҶдёҚжңғеҫһиіҮж–ҷеә«дёӯеҲӘйҷӨгҖӮ', '?ВҖ?пҗ§ВҖ???е”ійЈӣз‘јоқ„?жҡәоөҰ??п“„пҒҚ?пҒёпҠ®?оҹ жҘҡ?оўҖпјҠиқ·з¶Ҫ?йӣҝпүӢ??пҒёв—Ө?иҠ·оЁ’??All edges linked to an archived node are automatically faded in appearance but are not deleted from the database.', '{}', 'public', 'system', '2026-04-24 11:25:39.557633+00', NULL, 'e2889812266b17efc364454a6ee3ea5a6881e8250b720564bfa2dc84bbaddf20', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_fb0354ee', '1.0', 'ws_spec0001', 'ж–°еўһ MEMTRACE_TOKEN з’°еўғи®Ҡж•ё', 'Add MEMTRACE_TOKEN Environment Variable', 'factual', 'markdown', 'зӮәж”ҜжҸҙ `list_workspaces` еҸҠжңӘдҫҶеҜ«е…Ҙе·Ҙе…·еӯҳеҸ– `/api/v1/workspaces`пјҢж–°еўһ `MEMTRACE_TOKEN` з’°еўғи®Ҡж•ёгҖӮжӯӨи®Ҡж•ёе°Ү API token жіЁе…Ҙ `apiFetch` зҡ„ `Authorization: Bearer` жЁҷй ӯдёӯгҖӮ', 'The `MEMTRACE_TOKEN` environment variable is added to support `list_workspaces` and future writing tools in accessing `/api/v1/workspaces`. This variable injects the API token into the `Authorization: Bearer` header of `apiFetch`.', '{з’°еўғи®Ҡж•ё,api,иӘҚиӯү,е®үе…ЁжҖ§}', 'public', 'system', '2026-04-25 02:39:33.890766+00', NULL, '5a92752ad8e42bd741785135c860e72414dc35b7ea7f68525e8f904ee3b40f5f', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_f8057a39', '1.0', 'ws_spec0001', 'е·Ҙе…· description жӣҙж–°', 'Tool Description Update', 'procedural', 'markdown', '`search_nodes`гҖҒ`get_node`гҖҒ`traverse`гҖҒ`list_by_tag` зӯүе·Ҙе…·зҡ„жҸҸиҝ°е·Іжӣҙж–°пјҢж–°еўһдёҖиЎҢиӘӘжҳҺеҰӮдҪ•дҪҝз”Ё `workspace_id` еҸғж•ёжҹҘи©ўзү№е®ҡзҹҘиӯҳеә«пјҢжҲ–зңҒз•Ҙд»ҘдҪҝз”Ёй җиЁӯеҖј `MEMTRACE_WS`гҖӮ', 'The descriptions for tools like `search_nodes`, `get_node`, `traverse`, and `list_by_tag` have been updated to include a line explaining how to pass `workspace_id` to query a specific KB, or omit it to use the configured default (`MEMTRACE_WS`).', '{е·Ҙе…·,ж–Үд»¶,е·ҘдҪңеҚҖ}', 'public', 'system', '2026-04-25 02:39:37.786358+00', NULL, '619066f74e4abdca14e319bcd9cbfe613562619b098582a5070872003bddedae', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_f83d6e1b', '1.0', 'ws_spec0001', 'AI д»ЈзҗҶе·ҘдҪңжөҒзЁӢпјҡе»әз«Ӣж–°зҜҖй»һ', 'AI Agent Workflow: Create New Node', 'procedural', 'markdown', 'AI д»ЈзҗҶжҮүе‘јеҸ« `create_node` еҮҪж•ёдҫҶе»әз«Ӣж–°зҜҖй»һпјҢдёҰжҸҗдҫӣ `title_zh`гҖҒ`title_en`гҖҒ`content_type`гҖҒ`content_format`гҖҒ`body_zh` зӯүж¬„дҪҚгҖӮзү№еҲҘжҳҜпјҢAI д»ЈзҗҶеҝ…й ҲиЁӯе®ҡ `source_type: "ai"`гҖӮ', 'AI agents should call the `create_node` function to create new nodes, providing fields such as `title_zh`, `title_en`, `content_type`, `content_format`, and `body_zh`. Specifically, AI agents must set `source_type: "ai"`.', '{aiд»ЈзҗҶ,е·ҘдҪңжөҒзЁӢ,зҜҖй»һе»әз«Ӣ,api}', 'public', 'system', '2026-04-25 02:39:25.137437+00', NULL, '04fe85dcca072d61a5b4587e35961b2be16ec3bc52a01b288b2e17f13a480e33', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_71aebf92', '1.0', 'ws_spec0001', 'й©—ж”¶жғ…еўғпјҡжҹҘи©ўжҢҮе®ҡе·ҘдҪңеҚҖзҜҖй»һ', 'Acceptance Scenario: Query Specific Workspace Nodes', 'procedural', 'markdown', 'й©—ж”¶жғ…еўғд№ӢдёҖпјҡе‘јеҸ« `search_nodes(query="иӘҚиӯү", workspace_id="ws_project_abc")` жҮүиғҪжҲҗеҠҹжҹҘи©ў `ws_project_abc` е·ҘдҪңеҚҖдёӯзҡ„зҜҖй»һгҖӮ', 'One acceptance scenario: calling `search_nodes(query="иӘҚиӯү", workspace_id="ws_project_abc")` should successfully query nodes within the `ws_project_abc` workspace.', '{й©—ж”¶жё¬и©Ұ,е·ҘдҪңеҚҖ,жҹҘи©ў}', 'public', 'system', '2026-04-25 02:39:48.355492+00', NULL, '8afa92eb018c4301321a6ed7b199a7ec28ba488e9f2e899f75ef028ff4ea9e09', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_ff4e804e', '1.0', 'ws_spec0001', 'е…Ҙй–ҖзІҫйқҲиҮӘеӢ•йЎҜзӨәжўқд»¶', 'йӣҝиј»оң…?пҶҜ?ж’ оҺ”?ж’ оҺ—пҠ®?оҹЈпјҠиқ·з®ё?йҡһ?Onboarding Wizard Auto-Display Condition', 'factual', 'markdown', 'йҠқВҖ?еңіcompleted: true`еҡ—п—№иқҷ?еҲ»ВҖпҶҜ?ж’ оҺ”?ж’ оҺ”?йҠқпҡ—??иҠё?жҶҝиҲҗе…§??Once `completed: true`, the onboarding wizard is never shown automatically again.', 'йҠқВҖ?еңіcompleted: true`еҡ—п—№иқҷ?еҲ»ВҖпҶҜ?ж’ оҺ”?ж’ оҺ”?йҠқпҡ—??иҠё?жҶҝиҲҗе…§??Once `completed: true`, the onboarding wizard is never shown automatically again.', '{onboarding,ui,completion}', 'public', 'system', '2026-04-24 11:25:40.415959+00', NULL, '0c8adbf4e2f1b9f5bc07fac93f031d00d9a0cf53f41896d28bb69c72e0415ce9', 'ai', NULL, NULL, NULL, NULL, 0.593, 0.800, 1.000, 0.010, 0.500, 0, 0, 0, 1, 1, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_62d07b1d', '1.0', 'ws_spec0001', 'AI д»ЈзҗҶе·ҘдҪңжөҒзЁӢпјҡзўәиӘҚзҜҖй»һе»әз«ӢзӢҖж…Ӣ', 'AI Agent Workflow: Confirm Node Creation Status', 'procedural', 'markdown', 'еңЁ AI д»ЈзҗҶе‘јеҸ« `create_node` еҫҢпјҢиӢҘ API еӣһеӮі 201 зӢҖж…ӢзўјпјҢжҮүе‘јеҸ« `traverse(node.id)` зўәиӘҚйӮҠе·Іе»әз«ӢпјӣиӢҘеӣһеӮі 202 зӢҖж…ӢзўјдёҰеё¶жңү `review_id`пјҢеүҮжҮүе‘јеҸ« `list_review_queue()` зўәиӘҚеҜ©ж ёдҪҮеҲ—зӢҖж…ӢгҖӮ', 'After an AI agent calls `create_node`, if the API returns a 201 status code, it should call `traverse(node.id)` to confirm edge creation. If a 202 status code with a `review_id` is returned, it should call `list_review_queue()` to check the review queue status.', '{aiд»ЈзҗҶ,е·ҘдҪңжөҒзЁӢ,зҜҖй»һе»әз«Ӣ,api,еҜ©ж ёжөҒзЁӢ}', 'public', 'system', '2026-04-25 02:39:26.18783+00', NULL, '900865976521e0a50bd83f5ae1e63ce3cad6a2db9ff6e46516532a3dde144e24', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_1185cce5', '1.0', 'ws_spec0001', 'е»әз«Ӣ API йҮ‘й‘°', 'Create API Key', 'procedural', 'markdown', 'дҪҝз”Ё `curl` е‘Ҫд»Өеҗ‘ `/api/v1/users/me/api-keys` з«Ҝй»һзҷјйҖҒ POST и«ӢжұӮпјҢд»Ҙе»әз«ӢдёҖеҖӢж–°зҡ„ API йҮ‘й‘°гҖӮи«ӢжұӮйңҖеҢ…еҗ«жҺҲж¬Ҡ Bearer TokenгҖҒContent-Type зӮә `application/json`пјҢд»ҘеҸҠеҢ…еҗ«йҮ‘й‘°еҗҚзЁұе’ҢзҜ„еңҚпјҲдҫӢеҰӮ `kb:read`, `kb:write`пјүзҡ„ JSON иіҮж–ҷгҖӮ', 'Use a `curl` command to send a POST request to the `/api/v1/users/me/api-keys` endpoint to create a new API key. The request must include an Authorization Bearer Token, Content-Type as `application/json`, and JSON data containing the key name and scopes (e.g., `kb:read`, `kb:write`).', '{}', 'public', 'system', '2026-04-25 02:39:30.610529+00', NULL, '64f3676e69b048faf93b180a7bd9c33f59d965f34af7acd616c3933fa4b44cd7', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_76d6491f', '1.0', 'ws_spec0001', '.mcp.json иЁӯе®ҡжӘ”жӣҙж–°зӮәе–®еҜҰдҫӢеҜ«жі•', '.mcp.json Configuration Update to Single Instance', 'procedural', 'markdown', '`.mcp.json` иЁӯе®ҡжӘ”е·Іжӣҙж–°зӮәе–®еҜҰдҫӢеҜ«жі•пјҢз§»йҷӨдәҶе°ҚжҜҸеҖӢзҹҘиӯҳеә«дёҖеҖӢеҜҰдҫӢзҡ„дҫқиіҙпјҢдёҰж•ҙеҗҲдәҶ token иЁӯе®ҡгҖӮйҖҷз°ЎеҢ–дәҶй…ҚзҪ®пјҢдҪҝе…¶жӣҙжҳ“ж–јз®ЎзҗҶгҖӮ', 'The `.mcp.json` configuration file has been updated to a single-instance approach, removing the dependency on one instance per knowledge base and integrating token settings. This simplifies configuration and makes it easier to manage.', '{иЁӯе®ҡжӘ”,mcp,жһ¶ж§Ӣ,й…ҚзҪ®}', 'public', 'system', '2026-04-25 02:39:38.497095+00', NULL, '61e28dfaf329b22ab626103c29e89e1dc61b98f08be7a0c17c2ca073c04ef97c', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
