INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_e73ea399', '1.0', 'ws_spec0001', 'EDGE_GUIDE е…§е®№е®ҡзҫ©', 'EDGE_GUIDE Content Definition', 'factual', 'markdown', '`EDGE_GUIDE` еёёж•ёе®ҡзҫ©дәҶй—ңиҒҜйЎһеһӢиӘһж„ҸгҖҒж¬ҠйҮҚзҜ„еңҚгҖҒ`half_life_days` иӘӘжҳҺд»ҘеҸҠ 409 иЎқзӘҒиҷ•зҗҶж–№ејҸгҖӮ', 'The `EDGE_GUIDE` constant defines relation type semantics, weight range, `half_life_days` explanation, and 409 conflict handling.', '{edge_guide,edge,specification,documentation}', 'public', 'system', '2026-04-25 02:39:29.242927+00', NULL, '5fef9aae465627bf86285619c53a86bb7deaa85f2734000b16bad20efcd47632', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_c3e5a685', '1.0', 'ws_spec0001', 'иІўзҚ»иҖ…и§’иүІиғҪеҠӣи©іжғ…', 'Contributor Role Capabilities Detail', 'factual', 'markdown', 'иІўзҚ»иҖ…ж“ҒжңүжүҖжңүжӘўиҰ–иҖ…иғҪеҠӣпјҢдёҰеҸҜд»ҘжҸҗдәӨж–°зҜҖй»һгҖҒз·ЁијҜзҸҫжңүзҜҖй»һжҲ–ж–°/еҲӘйҷӨйӮҠзҡ„жҸҗжЎҲгҖӮйҖҷдәӣжҸҗжЎҲйҖІе…ҘеҜ©ж ёйҡҠеҲ—пјҢзӢҖж…ӢзӮә `pending_admin_review`пјҢзӣҙеҲ°з®ЎзҗҶе“Ўжү№еҮҶгҖӮиІўзҚ»иҖ…дёҚеҫ—жү№еҮҶиҮӘе·ұзҡ„жҸҗжЎҲгҖӮ', 'Contributors have all viewer capabilities and can submit proposals for new nodes, edits to existing nodes, or new/deleted edges. These proposals enter a review queue with `status = pending_admin_review` until an admin approves. A contributor may not approve their own proposals.', '{role,contributor,capabilities,proposal,review-queue}', 'public', 'system', '2026-04-24 11:25:40.561589+00', NULL, 'e9503d1f90e13846bc35650c0f983527ccabd9b7209e4b6faab958cab6bd02f8', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
