INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_d679d993', '1.0', 'ws_spec0001', 'MemTrace ж ёеҝғе“ІеӯёпјҡзҹҘиӯҳиҲҮзӯ–еұ•дәәй—ңдҝӮ', 'MemTrace Core Philosophy: Knowledge and Curator Relationship', 'factual', 'markdown', 'MemTrace зҡ„иЁӯиЁҲзҗҶеҝөи¶…и¶ҠдәҶе–®зҙ”зҡ„ж¬ҠйҷҗжЁЎеһӢпјҢй—Ўиҝ°дәҶзҹҘиӯҳиҲҮе…¶зӯ–еұ•дәәд№Ӣй–“зҡ„й—ңдҝӮгҖӮ', 'MemTrace''s design philosophy goes beyond a mere permissions model, articulating the relationship between knowledge and its curator.', '{memtrace,philosophy,knowledge-management}', 'public', 'system', '2026-04-24 11:27:02.088865+00', NULL, 'f8f87913529c03f880e7c1e82cea98b7b4b167dcf7d43215cacf3e98218bd995', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_bb9aff63', '1.0', 'ws_spec0001', 'з®ЎзҗҶе“Ўи§’иүІжҰӮиҰҪ', 'Admin Role Overview', 'factual', 'markdown', 'з®ЎзҗҶе“ЎжҳҜзҹҘиӯҳеә«зҡ„жүҖжңүиҖ…жҲ–з¶ӯиӯ·иҖ…гҖӮд»–еҖ‘ж“ҒжңүжүҖжңүиІўзҚ»иҖ…иғҪеҠӣгҖҒзӣҙжҺҘеҜ«е…Ҙж¬ҠйҷҗгҖҒжү№еҮҶжҲ–жӢ’зө•жҸҗжЎҲзҡ„иғҪеҠӣгҖҒз®ЎзҗҶжҲҗе“Ўд»ҘеҸҠи»ҹеҲӘйҷӨе’ҢжҒўеҫ©е·ҘдҪңеҚҖзҡ„иғҪеҠӣгҖӮ', 'Admins are repository owners or maintainers. They possess all contributor capabilities, direct write access, the ability to approve or reject proposals, manage members, and soft-delete and restore workspaces.', '{role,admin,capabilities}', 'public', 'system', '2026-04-24 11:25:40.503845+00', NULL, 'e887ffec2fead0932c9e9c9281169b35a204c219a609098713d149f87b622012', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
