INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_52ac8940', '1.0', 'ws_spec0001', 'зҙ”ж–Үжң¬ијёе…ҘжЁЎејҸ', 'Plain Text Input Mode', 'factual', 'markdown', 'еңЁ `plain` жЁЎејҸдёӢпјҢијёе…Ҙе…§е®№жңғжҢүеҺҹжЁЈеӯҳе„ІеңЁ `content.body` дёӯпјҢдёҚйҖІиЎҢд»»дҪ•жёІжҹ“жЁҷиЁҳгҖӮ', 'In `plain` mode, input is stored as-is in `content.body` with no rendering markup.', '{input-mode,plain-text}', 'public', 'system', '2026-04-24 11:25:39.391767+00', NULL, '0d46112da947dead20360dc05d449e40425556481707045ac95fe29254d918b3', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
