INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_7dfe253a', '1.0', 'ws_spec0001', 'MCP иә«д»Ҫй©—иӯү', 'MCP Authentication', 'factual', 'markdown', 'й©—иӯүжҳҜйҖҸйҒҺеӮійҒһ API йҮ‘й‘°е®ҢжҲҗзҡ„пјҢи©ІйҮ‘й‘°дҪңзӮә `MEMTRACE_API_KEY` з’°еўғи®ҠйҮҸпјҲstdio жЁЎејҸпјүжҲ– `Authorization` жЁҷй ӯпјҲHTTP жЁЎејҸпјүеӮійҒһгҖӮ', 'Authentication is via an API key passed as the `MEMTRACE_API_KEY` environment variable (stdio mode) or `Authorization` header (HTTP mode).', '{mcp,authentication,api-key,environment-variable,http-header}', 'public', 'system', '2026-04-24 11:25:40.347126+00', NULL, '40ba3456cf0cbbf4aa1cf85bbac939f6d6e95a7488dd0d987161188f20053de6', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_a003', '1.0', 'ws_spec0001', 'Review Queueпјҡдәәе·ҘеҜ©ж ё AI иҗғеҸ–зөҗжһң', 'Review Queue: human review of AI-extracted candidates', 'procedural', 'plain', 'AI иҗғеҸ–зҡ„еҖҷйҒёзҜҖй»һдёҚиҮӘеӢ•йҖІе…ҘзҹҘиӯҳеә«пјҢеҝ…й ҲйҖҡйҒҺдәәе·ҘеҜ©ж ёгҖӮдёүзЁ®ж“ҚдҪңпјҡAcceptпјҲжҺҘеҸ—еҺҹжЁЈпјүгҖҒEdit then AcceptпјҲдҝ®ж”№еҫҢжҺҘеҸ—пјүгҖҒRejectпјҲжҚЁжЈ„пјүгҖӮж”ҜжҸҙжү№ж¬Ўж“ҚдҪңпјҲAccept all / Reject allпјүгҖӮиҮіе°‘йңҖжҺҘеҸ—дёҖеҖӢзҜҖй»һжүҚиғҪй—ңй–үеҜ©ж ёжӯҘй©ҹгҖӮеҜ©ж ёе®ҢжҲҗеҫҢпјҢиў«жҺҘеҸ—зҡ„зҜҖй»һд»ҘжӯЈзўәзҡ„ source_type еҜ«е…ҘзҹҘиӯҳеә«пјҢиў«жӢ’зө•зҡ„еҖҷйҒёж°ёд№…дёҹжЈ„гҖӮйҖҷжҳҜ MemTrace зўәдҝқ AI з”ҹжҲҗе…§е®№дёҚжұЎжҹ“зҹҘиӯҳеә«зҡ„ж ёеҝғж©ҹеҲ¶гҖӮ', 'AI-extracted candidate nodes do not enter the Knowledge Base automatically вҖ” they must pass human review. Three actions: Accept (as-is), Edit then Accept (modify before committing), Reject (discard). Bulk operations (Accept all / Reject all) are supported. At least one node must be accepted before the review step can be closed. After review, accepted nodes are written with the correct source_type; rejected candidates are permanently discarded. This is MemTrace''s core mechanism for preventing AI-generated content from polluting the Knowledge Base.', '{ai,review-queue,quality-control,ingestion}', 'public', 'memtrace-spec', '2026-04-11 00:00:00+00', NULL, 'f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.950, 0.900, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_i003', '1.0', 'ws_spec0001', 'MCP ServerпјҡAI Agent ж•ҙеҗҲ', 'MCP Server: AI agent integration', 'factual', 'markdown', 'MemTrace еҜҰдҪң **Model Context Protocol (MCP)**пјҢи®“ AI agentпјҲеҰӮ Claude CodeпјүеҸҜд»Ҙе°Ү MemTrace зҹҘиӯҳеә«дҪңзӮә context providerпјҢз„ЎйңҖзӣҙжҺҘи®ҖеҸ–иҰҸж јж–Үд»¶гҖӮ

**Transport**пјҡзӣ®еүҚеғ…ж”ҜжҸҙ stdioпјҲ`node packages/mcp/dist/index.js`пјүгҖӮ

**з•¶еүҚеҜҰдҪңе·Ҙе…·пјҲToolsпјү**пјҡ

| е·Ҙе…· | иӘӘжҳҺ |
|------|------|
| `search_nodes` | й—ңйҚөеӯ—жҗңе°ӢзҜҖй»һпјҲдёӯиӢұж–ҮзҡҶеҸҜпјүпјҢеӣһеӮіе®Ңж•ҙе…§е®№ |
| `get_node` | дҫқ ID еҸ–еҫ—зү№е®ҡзҜҖй»һе®Ңж•ҙе…§е®№иҲҮ metadata |
| `traverse` | еҸ–еҫ—зҜҖй»һеҸҠе…¶дёҠдёӢжёёй—ңиҒҜпјҲdepth=1 жҲ– 2пјү|
| `list_by_tag` | дҫқ tag еҲ—еҮәжүҖжңүзҜҖй»һ |

**з’°еўғи®Ҡж•ё**пјҡ
- `MEMTRACE_API`пјҡAPI base URLпјҲй җиЁӯ `http://localhost:8000/api/v1`пјү
- `MEMTRACE_WS`пјҡWorkspace IDпјҲй җиЁӯ `ws_spec0001`пјү
- `MEMTRACE_LANG`пјҡйЎҜзӨәиӘһиЁҖпјҲй җиЁӯ `zh-TW`пјү

**зҸҫжңүйҷҗеҲ¶**пјҡ
жҜҸеҖӢ MCP server еҜҰдҫӢеҸӘиғҪжҹҘи©ўе–®дёҖе·ҘдҪңеҚҖпјҲз”ұ `MEMTRACE_WS` еӣәе®ҡпјүгҖӮиӢҘйңҖжҹҘи©ўеӨҡеҖӢзҹҘиӯҳеә«пјҢзӣ®еүҚ workaround жҳҜеңЁ `.mcp.json` дёӯзӮәжҜҸеҖӢе·ҘдҪңеҚҖе•ҹеӢ•зҚЁз«ӢеҜҰдҫӢпјҢдҪҶе·Ҙе…·еҗҚзЁұзӣёеҗҢжңғйҖ жҲҗ AI agent ж··ж·ҶгҖӮ

**е·ІиҰҸеҠғдҪҶе°ҡжңӘеҜҰдҪң**пјҡ
- еӨҡе·ҘдҪңеҚҖж”ҜжҸҙпјҡе·Ҙе…·еҠ е…ҘеҸҜйҒё `workspace_id` еҸғж•ё + `list_workspaces` е·Ҙе…·
- ResourcesпјҲ`memtrace://node/{id}` зӯү URI и®ҖеҸ–пјү
- еҜ«е…Ҙе·Ҙе…·пјҲ`create_node`гҖҒ`update_node`гҖҒ`create_edge`пјү
- HTTP + SSE transport
- `traverse_edge` и§ёзҷј co-access boost

Agent жҜҸж¬ЎжІҝ Edge з§»еӢ•жҷӮжҮүе‘јеҸ« traverse е·Ҙе…·пјҢи®“еёёз”Ёи·Ҝеҫ‘дҝқжҢҒжҙ»иәҚпјҢжҠөжҠ— decayгҖӮ', 'MemTrace implements the **Model Context Protocol (MCP)**, allowing AI agents (e.g. Claude Code) to use MemTrace as a context provider without reading raw spec documents.

**Transport**: stdio only for now (`node packages/mcp/dist/index.js`).

**Currently implemented tools**:

| Tool | Description |
|------|-------------|
| `search_nodes` | Keyword search across nodes (Chinese and English), returns full content |
| `get_node` | Retrieve a specific node by ID with full content and metadata |
| `traverse` | Get a node plus its upstream/downstream associations (depth=1 or 2) |
| `list_by_tag` | List all nodes with a specific tag |

**Environment variables**:
- `MEMTRACE_API`: API base URL (default `http://localhost:8000/api/v1`)
- `MEMTRACE_WS`: Workspace ID (default `ws_spec0001`)
- `MEMTRACE_LANG`: Display language (default `zh-TW`)

**Current limitation**: Each MCP server instance is locked to a single workspace (set by `MEMTRACE_WS`). To query multiple knowledge bases, the current workaround is to start a separate instance per workspace in `.mcp.json`, but identical tool names cause confusion for AI agents.

**Planned but not yet implemented**:
- Multi-workspace support: optional `workspace_id` parameter on all tools + `list_workspaces` tool
- Resources (`memtrace://node/{id}` URI reads)
- Write tools (`create_node`, `update_node`, `create_edge`)
- HTTP + SSE transport
- `traverse_edge` to trigger co-access boost

Agents should call traverse when following an edge, keeping frequently used paths alive against decay.', '{mcp,ai-agent,integration,api}', 'public', 'system', '2026-04-11 00:00:00+00', NULL, 'c6d7e8f9a4b5c6d7e8f9a4b5c6d7e8f9a4b5c6d7e8f9a4b5c6d7e8f9a4b5c6d7', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.950, 0.900, 0, 0, 0, 3, 2, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_k004', '1.0', 'ws_spec0001', 'е·ҘдҪңеҚҖз”ҹе‘ҪйҖұжңҹиҲҮи»ҹеҲӘйҷӨпјҲ30 еӨ©еҜ¬йҷҗжңҹпјү', 'Workspace lifecycle and soft-delete (30-day grace period)', 'procedural', 'plain', 'е·ҘдҪңеҚҖжңүдёүеҖӢзӢҖж…ӢпјҡactiveпјҲжӯЈеёёпјүгҖҒpending_deletionпјҲи»ҹеҲӘйҷӨдёӯпјүгҖҒdeletedпјҲе·Іжё…йҷӨпјүгҖӮ

и»ҹеҲӘйҷӨи§ёзҷјпјҡadmin е‘јеҸ« DELETE /workspaces/{ws_id}
- иЁӯе®ҡ status = pending_deletionгҖҒdeleted_at = NOW()
- йқһ admin жҲҗе“Ўз«ӢеҚіеӨұеҺ»еӯҳеҸ–
- Admin/owner дҝқз•ҷе”Ҝи®ҖеӯҳеҸ–пјҲеҸҜеҢҜеҮәиіҮж–ҷпјү
- йҖҡзҹҘйғөд»¶пјҡз¬¬ 0 еӨ©пјҲеҲӘйҷӨе•ҹеӢ•пјүгҖҒз¬¬ 25 еӨ©пјҲ5 еӨ©иӯҰе‘ҠпјүгҖҒз¬¬ 30 еӨ©пјҲжңҖзөӮжё…йҷӨпјү

йӮ„еҺҹпјҡеңЁеҜ¬йҷҗжңҹе…§ admin е‘јеҸ« POST /workspaces/{ws_id}/restore
- status еӣһеҲ° activeпјҢdeleted_at жё…з©әпјҢжүҖжңүжҲҗе“ЎеӯҳеҸ–жҒўеҫ©

иҮӘеӢ•жё…йҷӨпјҡжҜҸж—ҘиғҢжҷҜжҺ’зЁӢпјҢжё…йҷӨ status = pending_deletion AND deleted_at < NOW() - INTERVAL ''30 days'' зҡ„е·ҘдҪңеҚҖпјҲCASCADE DELETEпјҡзҜҖй»һгҖҒйӮҠгҖҒжҲҗе“ЎгҖҒйӮҖи«ӢгҖҒе°Қи©ұзҙҖйҢ„е…ЁйғЁеҲӘйҷӨпјҢдёҚеҸҜйӮ„еҺҹпјүгҖӮ

KB йЎһеһӢеҜ¬йҷҗжңҹе·®з•°пјҡ
- evergreenпјҡ30 еӨ©
- ephemeralпјҡ7 еӨ©

Schema ж–°еўһпјҡ
ALTER TABLE workspaces ADD COLUMN status TEXT NOT NULL DEFAULT ''active'' CHECK (status IN (''active'',''pending_deletion'',''deleted'')), ADD COLUMN deleted_at TIMESTAMPTZ;', 'Workspaces move through three states: active (normal), pending_deletion (soft-deleted, grace period active), deleted (purged from DB).

Soft-delete trigger: admin calls DELETE /workspaces/{ws_id}
- Sets status = pending_deletion, deleted_at = NOW()
- Non-admin members immediately lose access
- Admin/owner retains read-only access (for data export)
- Email notifications: day 0 (deletion initiated), day 25 (5-day warning), day 30 (final purge)

Restoration: any admin calls POST /workspaces/{ws_id}/restore within the grace period
- status returns to active, deleted_at is cleared, all member access is restored

Automatic purge: daily background job deletes workspaces where status = ''pending_deletion'' AND deleted_at < NOW() - INTERVAL ''30 days''. This is a hard CASCADE DELETE вҖ” all nodes, edges, members, invites, and chat sessions are deleted. Cannot be undone.

Grace period by KB type:
- evergreen: 30 days
- ephemeral: 7 days

Schema change:
ALTER TABLE workspaces ADD COLUMN status TEXT NOT NULL DEFAULT ''active'' CHECK (status IN (''active'',''pending_deletion'',''deleted'')), ADD COLUMN deleted_at TIMESTAMPTZ;', '{workspace,lifecycle,soft-delete,grace-period,deletion,restore}', 'public', 'system', '2026-04-12 00:00:00+00', NULL, 'e2f3a4b5c6d7e2f3a4b5c6d7e2f3a4b5c6d7e2f3a4b5c6d7e2f3a4b5c6d7e2f3', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.900, 0.900, 0, 0, 0, 4, 2, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_p002', '1.0', 'ws_spec0001', 'зӮәзҹҘиӯҳеӮіжүҝиҖҢиЁӯиЁҲ', 'Designed for knowledge inheritance', 'context', 'plain', 'MemTrace зӮәгҖҢйқһдҪңиҖ…гҖҚиЁӯиЁҲгҖӮз„Ўи«–жҳҜеүӣеҠ е…Ҙзҡ„еңҳйҡҠжҲҗе“ЎгҖҒдёӯйҖ”еҠ е…Ҙзҡ„еҚ”дҪңиҖ…пјҢйӮ„жҳҜеңЁйҷҢз”ҹжғ…еўғдёӯйҒӢдҪңзҡ„ AI agentпјҢйғҪиғҪеҫһд»»дҪ•зҜҖй»һйҖІе…ҘзҹҘиӯҳеә«пјҢжІҝи‘— Edge жүҫеҲ°жүҖжңүзӣёй—ңе…§е®№пјҢдёҚйңҖиҰҒеҺҹдҪңиҖ…еј•е°ҺгҖӮжҜҸеҖӢзҜҖй»һиЁӯиЁҲдёҠиҰҒиҮӘзөҰиҮӘи¶іеҲ°еҸҜд»ҘзҚЁз«Ӣй–ұи®ҖпјҢеҗҢжҷӮеҸҲйҖҸйҒҺ Edge йҖЈзөҗи®“и®ҖиҖ…еҸҜд»ҘиҮӘз„¶ж·ұе…ҘжҺўзҙўгҖӮ', 'MemTrace is designed for the reader who was not there when the knowledge was created. A new team member, a late collaborator, or an AI agent in an unfamiliar context вҖ” all can enter at any node and navigate by following edges, without needing the original author to guide them. Each node is self-contained enough to read in isolation, yet connected enough that following its edges leads naturally to everything related.', '{philosophy,core,design-principle,inheritance}', 'public', 'memtrace-spec', '2026-04-11 00:00:00+00', NULL, 'b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.950, 0.900, 0, 0, 0, 1, 1, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_a001', '1.0', 'ws_spec0001', 'AI Provider иҲҮ API Key иҮӘз®Ў', 'AI provider and self-managed API keys', 'procedural', 'markdown', 'MemTrace дёҚиҮӘзҮҹ AI жҺЁи«–жңҚеӢҷгҖӮжүҖжңү AI еҠҹиғҪз”ұдҪҝз”ЁиҖ…йҒёж“Үзҡ„дҫӣжҮүе•ҶжҸҗдҫӣгҖӮ

**е®ҳж–№е…§е»ә Provider**пјҡ

| Provider | иӯҳеҲҘзўј | й җиЁӯ Chat жЁЎеһӢ | Embedding жЁЎеһӢ | з¶ӯеәҰ |
|----------|--------|---------------|---------------|------|
| OpenAI | `openai` | `gpt-4o-mini` | `text-embedding-3-small` | 1536 |
| Anthropic | `anthropic` | `claude-haiku-4-5-20251001` | `voyage-3-lite` | 1024 |
| Google Gemini | `gemini` | `gemini-2.0-flash` | `text-embedding-004` | 768 |
| OllamaпјҲиҮӘз®Ўпјү| `ollama` | `llama3`пјҲеҸҜи®Ҡпјү| `nomic-embed-text` | еҸҜи®Ҡ |

**Ollama зү№еҲҘиӘӘжҳҺ**пјҡдёҚйңҖ API KeyпјҢж”№еЎ« `base_url`пјҲй җиЁӯ `http://localhost:11434`пјүгҖӮж”ҜжҸҙ `auth_mode: none`пјҲжң¬ж©ҹпјүиҲҮ `bearer`пјҲReverse Proxyпјүе…©зЁ®иӘҚиӯүжЁЎејҸгҖӮEmbedding з¶ӯеәҰдҫқжүҖйҒёжЁЎеһӢжұәе®ҡпјҲ`nomic-embed-text`=768гҖҒ`mxbai-embed-large`=1024пјүпјҢ**е»әз«Ӣе·ҘдҪңеҚҖеҫҢдёҚеҸҜжӣҙж”№**гҖӮи©іиҰӢ `docs/ollama-deployment.md`гҖӮ

**Embedding з¶ӯеәҰйҷҗеҲ¶**пјҡжҜҸеҖӢе·ҘдҪңеҚҖзҡ„ embedding з¶ӯеәҰеңЁе»әз«ӢжҷӮеӣәе®ҡпјҲ`workspaces.embedding_provider` + `embedding_dim`пјүпјҢ**дёҚеҸҜи®Ҡжӣҙ**гҖӮдёҚеҗҢ provider з”ўз”ҹзҡ„еҗ‘йҮҸз¶ӯеәҰдёҚеҗҢпјҢз„Ўжі•и·Ё provider жҜ”ијғ cosine similarityгҖӮ

**API Key е„Іеӯҳ**пјҡCLI еӯҳж–ј `~/.memtrace/config.json`пјҲchmod 600пјүпјҢUI еӯҳж–јеҠ еҜҶеҜ«е…Ҙ `user_ai_keys`пјҲOllama еҸҰеӯҳ `base_url` иҲҮ `auth_token`пјүгҖӮKey **ж°ёдёҚ**еӮійҖҒиҮі MemTrace дјәжңҚеҷЁд»ҘеӨ–зҡ„д»»дҪ•ең°ж–№гҖӮ

**зӨҫзҫӨ Provider**пјҡйҖҸйҒҺ `packages/api/core/ai.py` зҡ„ `AIProvider` Protocol еҸҜеҠ е…ҘжӣҙеӨҡ providerпјҲMistralгҖҒCohereгҖҒvLLM зӯүпјүгҖӮеҜҰдҪңеҫҢеңЁ `PROVIDER_REGISTRY` иЁ»еҶҠеҚіеҸҜпјҢдёҚйңҖдҝ®ж”№ router жҲ–иіҮж–ҷеә« schemaгҖӮ

**жңӘдҫҶе•ҶжҘӯжЁЎејҸ**пјҡеҸҜиғҪжҸҗдҫӣ MemTrace д»Јз®ЎйЎҚеәҰпјҲе…ҚиІ»еұӨ + д»ҳиІ»ж–№жЎҲпјүпјӣжһ¶ж§ӢйҖҸйҒҺ provider interface жҠҪиұЎпјҢж—ҘеҫҢеҲҮжҸӣдёҚеҪұйҹҝдёҠеұӨйӮҸијҜгҖӮ', 'MemTrace does not operate its own AI inference service. All AI features are powered by the user''s chosen provider.

**Officially built-in providers**:

| Provider | Identifier | Default chat model | Embedding model | Dim |
|----------|------------|--------------------|-----------------|-----|
| OpenAI | `openai` | `gpt-4o-mini` | `text-embedding-3-small` | 1536 |
| Anthropic | `anthropic` | `claude-haiku-4-5-20251001` | `voyage-3-lite` | 1024 |
| Google Gemini | `gemini` | `gemini-2.0-flash` | `text-embedding-004` | 768 |
| Ollama (self-hosted) | `ollama` | `llama3` (variable) | `nomic-embed-text` | Variable |

**Ollama notes**: No API key required. Configure `base_url` (default `http://localhost:11434`) and `auth_mode`: `none` (local) or `bearer` (reverse proxy). Embedding dimension depends on the chosen model (`nomic-embed-text`=768, `mxbai-embed-large`=1024) and is **immutable after workspace creation**. See `docs/ollama-deployment.md`.

**Embedding dimension constraint**: Each workspace fixes its embedding dimension at creation time (`workspaces.embedding_provider` + `embedding_dim`) and it is **immutable**. Different providers produce vectors of different dimensions; nodes embedded with different models cannot be compared via cosine similarity.

**API key storage**: CLI in `~/.memtrace/config.json` (chmod 600); UI encrypted in `user_ai_keys` (Ollama also stores `base_url` and `auth_token`). Keys are **never** transmitted outside the MemTrace server.

**Community providers**: Add more providers via the `AIProvider` Protocol in `packages/api/core/ai.py` (Mistral, Cohere, vLLM, etc.). Implement and register in `PROVIDER_REGISTRY` вҖ” no router or schema changes needed.

**Future business model**: a managed credit option (free tier + paid) may be introduced. The provider interface abstraction lets this swap in without touching extraction logic.', '{ai,api-key,provider,security,gemini,ollama,embedding}', 'public', 'memtrace-spec', '2026-04-11 00:00:00+00', '2026-04-29 00:00:00+00', 'd6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.950, 0.900, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_a005', '1.0', 'ws_spec0001', 'Analytics е„ҖиЎЁжқҝиҲҮ Token ж•ҲзҺҮе ұе‘Ҡ', 'Analytics dashboard and token efficiency report', 'procedural', 'markdown', '## KB еҒҘеә·ж‘ҳиҰҒ

`GET /workspaces/{ws_id}/analytics` еӣһеӮід»ҘдёӢж¬„дҪҚпјҲ30 ж—ҘиҰ–зӘ—пјүпјҡ

| ж¬„дҪҚ | иӘӘжҳҺ |
|------|------|
| `total_nodes` | жҙ»иәҚзҜҖй»һзёҪж•ё |
| `active_edges` | weight > 0.3 зҡ„жҙ»иәҚйӮҠж•ё |
| `orphan_node_count` | жІ’жңүд»»дҪ•жҙ»иәҚйӮҠзҡ„еӯӨз«ӢзҜҖй»һж•ё |
| `avg_trust_score` | е·ҘдҪңеҚҖе№іеқҮ trust_score |
| `faded_edge_ratio` | faded йӮҠдҪ”е…ЁйғЁйӮҠзҡ„жҜ”дҫӢ |
| `monthly_traversal_count` | иҝ‘ 30 ж—Ҙиө°иЁӘзёҪж¬Ўж•ё |
| `top_nodes` | иө°иЁӘж¬Ўж•ёжңҖй«ҳзҡ„ 5 еҖӢзҜҖй»һ |
| `traversal_trend` | йҖҗж—Ҙиө°иЁӘжҠҳз·ҡиіҮж–ҷпјҲ30 еӨ©пјү |
| `kb_type_metrics` | KB йЎһеһӢж„ҹзҹҘжҢҮжЁҷпјҲиҰӢдёӢпјү|

**KB йЎһеһӢж„ҹзҹҘжҢҮжЁҷ**пјҡ
- `evergreen`пјҡ`isolated_subgraph_count`пјҲеӯӨз«Ӣеӯҗең–ж•ёпјүгҖҒ`avg_edges_per_node`
- `operational/ephemeral`пјҡ`never_traversed_ratio`гҖҒ`avg_days_between_traversals`

**иӯҰзӨәйӮҸијҜпјҲUIпјү**пјҡ
- `evergreen` + `orphan_node_count > 0` вҶ’ ж©ҳиүІиӯҰзӨә
- йқһ evergreen + `never_traversed_ratio > 0.3` вҶ’ й»ғиүІиӯҰзӨә

## Token ж•ҲзҺҮе ұе‘Ҡ

`GET /workspaces/{ws_id}/analytics/token-efficiency` еӣһеӮіпјҡ

| ж¬„дҪҚ | иӘӘжҳҺ |
|------|------|
| `avg_tokens_per_query` | жң¬жңҲ MCP е‘јеҸ«е№іеқҮеӣһеӮі token ж•ё |
| `estimated_full_doc_tokens` | е…Ёж–Үи®ҖеҸ–зҡ„дј°з®— token ж•ёпјҲbody еӯ—е…ғж•ё / 4пјү|
| `savings_ratio` | `1 - avg_per_query / full_doc`пјҲзҜҖзңҒжҜ”дҫӢпјү|
| `monthly_query_count` | жң¬жңҲ MCP е‘јеҸ«ж¬Ўж•ё |

иіҮж–ҷдҫҶжәҗпјҡ`mcp_query_logs` иЎЁгҖӮжҜҸж¬Ў MCP read toolпјҲsearch_nodes / traverse / get_node / list_by_tag / vote_trustпјүе‘јеҸ«еҫҢйқһеҗҢжӯҘеҜ«е…ҘдёҖзӯҶ logпјҢиЁҳйҢ„ `tool_name`гҖҒ`result_node_count`гҖҒ`estimated_tokens`гҖҒ`provider`гҖӮ

## UI е…ғд»¶

`packages/ui/src/AnalyticsDashboard.tsx`пјҡ4 ж јжҢҮжЁҷеҚЎзүҮ + 30 ж—Ҙиө°иЁӘжҠҳз·ҡең– + Top Nodes жё…е–® + Token ж•ҲзҺҮеҚҖеЎҠ + KB йЎһеһӢжҢҮжЁҷж јгҖӮйҖҸйҒҺ workspace и©іжғ…й Ғзҡ„ Analytics еҲҶй Ғй–Ӣе•ҹгҖӮ', '## KB health summary

`GET /workspaces/{ws_id}/analytics` returns the following (30-day window):

| Field | Description |
|-------|-------------|
| `total_nodes` | Total active node count |
| `active_edges` | Edges with weight > 0.3 |
| `orphan_node_count` | Nodes with no active edges |
| `avg_trust_score` | Workspace-wide average trust_score |
| `faded_edge_ratio` | Ratio of faded edges to all edges |
| `monthly_traversal_count` | Total traversals in the last 30 days |
| `top_nodes` | Top-5 nodes by traversal count |
| `traversal_trend` | Per-day traversal data (30 days) |
| `kb_type_metrics` | KB-type-aware metrics (see below) |

**KB-type-aware metrics**:
- `evergreen`: `isolated_subgraph_count`, `avg_edges_per_node`
- `operational/ephemeral`: `never_traversed_ratio`, `avg_days_between_traversals`

**Alert logic (UI)**:
- `evergreen` + `orphan_node_count > 0` вҶ’ orange alert
- non-evergreen + `never_traversed_ratio > 0.3` вҶ’ yellow alert

## Token efficiency report

`GET /workspaces/{ws_id}/analytics/token-efficiency` returns:

| Field | Description |
|-------|-------------|
| `avg_tokens_per_query` | Average tokens returned per MCP call this month |
| `estimated_full_doc_tokens` | Estimated full-read tokens (body char count / 4) |
| `savings_ratio` | `1 - avg_per_query / full_doc` |
| `monthly_query_count` | MCP call count this month |

Data source: `mcp_query_logs` table. Each MCP read tool call (search_nodes / traverse / get_node / list_by_tag / vote_trust) writes one log entry asynchronously, recording `tool_name`, `result_node_count`, `estimated_tokens`, and `provider`.

## UI component

`packages/ui/src/AnalyticsDashboard.tsx`: 4-card metric grid + 30-day traversal sparkline + Top Nodes list + token efficiency block + KB-type metrics grid. Opened via the Analytics tab in the workspace detail view.', '{analytics,dashboard,token-efficiency,kb-health,mcp-logs,ui}', 'public', 'system', '2026-04-29 00:00:00+00', NULL, '', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.950, 0.900, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_p001', '1.0', 'ws_spec0001', 'зҹҘиӯҳйҖҸйҒҺйҖЈзөҗиҖҢйқһз©ҚзҙҜ', 'Knowledge through connection, not accumulation', 'context', 'plain', 'MemTrace зҡ„ж ёеҝғеүҚжҸҗпјҡзҹҘиӯҳдёҚйңҖиҰҒеӯҳеңЁж–јйҫҗеӨ§зҡ„ж–Үд»¶дёӯгҖӮжҜҸеҖӢзҜҖй»һеҸӘжҚ•жҚүдёҖеҖӢжғіжі•пјҢеғ№еҖјдҫҶиҮӘзҜҖй»һд№Ӣй–“зҡ„йҖЈзөҗз¶ІзөЎгҖӮзҜҖй»һжң¬иә«иј•йҮҸпјҢдҪҶйҖҸйҒҺй—ңиҒҜжҖ§еҪўжҲҗйҫҗеӨ§зҡ„зҹҘиӯҳеә«гҖӮзҹҘиӯҳеә«зҡ„иҰҸжЁЎдёҚжҳҜз”ұе–®дёҖзҜҖй»һзҡ„еӨ§е°Ҹжұәе®ҡпјҢиҖҢжҳҜз”ұзҜҖй»һд№Ӣй–“й—ңдҝӮзҡ„еҜҶеәҰиҲҮе“ҒиіӘжұәе®ҡгҖӮ', 'The core premise of MemTrace: knowledge does not need to live in large, monolithic documents. Each node captures one idea. Value emerges from the network of relationships between nodes. A node alone is lightweight; connected to others, it becomes part of a knowledge base whose scale is determined by the density and quality of its relationships, not the size of any single entry.', '{philosophy,core,design-principle}', 'public', 'memtrace-spec', '2026-04-11 00:00:00+00', NULL, 'a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.950, 0.900, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_a004', '1.0', 'ws_spec0001', 'е°Қи©ұејҸе•Ҹзӯ”пјҲConversational Q&Aпјү', 'Conversational Q&A against the knowledge base', 'procedural', 'plain', 'viewer д»ҘдёҠи§’иүІеҸҜе°ҚзҹҘиӯҳеә«йҖІиЎҢиҮӘз„¶иӘһиЁҖе•Ҹзӯ”гҖӮQ&A зӮәе”Ҝи®Җж“ҚдҪңпјҢдёҚдҝ®ж”№зҹҘиӯҳеә«е…§е®№гҖӮ

еҹ·иЎҢжөҒзЁӢпјҡ
1. дҪҝз”ЁиҖ…еӮійҖҒиЁҠжҒҜ
2. search_nodes(query) вҶ’ еҸ–еҫ—жңҖзӣёй—ңзҡ„ 5 еҖӢзҜҖй»һ
3. traverse(жңҖй«ҳеҲҶзҜҖй»һ, depth=1) вҶ’ иЈңе……й„°иҝ‘дёҠдёӢж–ҮпјҲеҸҜйҒёпјү
4. зө„еҗҲ promptпјҡsystem иӘӘжҳҺпјҲеҸӘдҪҝз”ЁжҸҗдҫӣзҡ„зҜҖй»һдҪңзӯ”пјҢдёҰеј•з”ЁзҜҖй»һ IDпјү+ зҜҖй»һе…§е®№ + дҪҝз”ЁиҖ…е•ҸйЎҢ
5. е‘јеҸ« AIпјҲдҪҝз”Ёе·ҘдҪңеҚҖ AI provider иЁӯе®ҡпјҢВ§16.5пјү
6. еӣһеӮіпјҡanswer + cited_nodes[] + tokens_used + session_id

APIпјҡ
- POST /workspaces/{ws_id}/chat вҖ” зҷјйҖҒиЁҠжҒҜпјҲеӮіе…Ҙ session_id еҸҜе»¶зәҢе°Қи©ұпјҢдёҚеӮіеүҮе»әз«Ӣж–° sessionпјү
- GET /workspaces/{ws_id}/chat/sessions вҖ” еҲ—еҮәдҪҝз”ЁиҖ…зҡ„ session жё…е–®
- GET /workspaces/{ws_id}/chat/sessions/{session_id} вҖ” еҸ–еҫ—е®Ңж•ҙе°Қи©ұзҙҖйҢ„

еӨҡијӘе°Қи©ұпјҡsession дёӯжңҖиҝ‘ 10 еүҮиЁҠжҒҜжңғдёҖиө·йҖҒе…Ҙ context window д»Ҙж”ҜжҸҙйҖЈзәҢе•Ҹзӯ”гҖӮ

Schemaпјҡchat_sessionsпјҲid, workspace_id, user_id, created_at, updated_atпјүе’Ң chat_messagesпјҲid, session_id, role user/assistant, content, cited_nodes[], tokens_used, created_atпјүгҖӮ

жіЁж„ҸпјҡеҚідҪҝжҳҜ public е·ҘдҪңеҚҖпјҢQ&A д№ҹйңҖиҰҒзҷ»е…ҘгҖӮжңӘиӘҚиӯүдҪҝз”ЁиҖ…з„Ўжі•дҪҝз”ЁжӯӨеҠҹиғҪгҖӮ', 'Any member with viewer role or above can ask natural-language questions against a workspace''s KB. Q&A is read-only вҖ” it never writes to the KB.

Execution flow:
1. User sends a message
2. search_nodes(query) вҶ’ retrieves top-5 relevant nodes
3. traverse(top node, depth=1) вҶ’ adds neighbour context (optional, improves multi-hop answers)
4. Build prompt: system instruction (answer only from provided nodes, cite node IDs) + node content blocks + user question
5. Call AI (uses workspace AI provider config, В§16.5)
6. Return: answer + cited_nodes[] + tokens_used + session_id

API:
- POST /workspaces/{ws_id}/chat вҖ” send message (pass session_id to continue a conversation; omit to start a new session)
- GET /workspaces/{ws_id}/chat/sessions вҖ” list the caller''s sessions
- GET /workspaces/{ws_id}/chat/sessions/{session_id} вҖ” get full message history

Multi-turn: the last 10 messages in the session are included in the context window for conversational continuity.

Schema: chat_sessions (id, workspace_id, user_id, created_at, updated_at) and chat_messages (id, session_id, role user/assistant, content, cited_nodes[], tokens_used, created_at).

Note: Q&A requires authentication even on public workspaces. Unauthenticated users cannot use this feature.', '{ai,chat,q&a,conversational,session,read-only}', 'public', 'system', '2026-04-12 00:00:00+00', NULL, 'f3a4b5c6d7e8f3a4b5c6d7e8f3a4b5c6d7e8f3a4b5c6d7e8f3a4b5c6d7e8f3a4', 'human', NULL, NULL, NULL, NULL, 0.950, 0.950, 1.000, 0.950, 0.900, 0, 0, 0, 3, 1, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_d0961cfa', '1.0', 'ws_spec0001', 'иЁҳжҶ¶зҜҖй»һз·ЁијҜеҷЁеӯҳеҸ–ж–№жі•', 'Memory Node Editor Access Methods', 'procedural', 'markdown', 'з·ЁијҜеҷЁеҸҜеҫһең–иӯңиҰ–ең–пјҲйҖҸйҒҺе·Ҙе…·еҲ—жҢүйҲ•жҲ–йӣҷж“Ҡз©әзҷҪз•«еёғеҚҖеҹҹпјүд»ҘеҸҠзҜҖй»һзҡ„дёҠдёӢж–ҮиҸңе–®еӯҳеҸ–гҖӮ', 'The editor is accessible from the Graph View (via a toolbar button or double-clicking an empty canvas area) and from the node''s context menu.', '{editor,access,ui}', 'public', 'system', '2026-04-24 11:25:39.331044+00', NULL, '8a3d4055ab327d3e4acebfb2c8f2e9c165b22d5051ede17ec4d37ec45d66869a', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_05ce17d1', '1.0', 'ws_spec0001', 'AI дҪҝз”Ёж—ҘиӘҢиЎЁзҙўеј•', 'AI Usage Log Table Indexes', 'factual', 'markdown', 'еңЁ `ai_usage_log` иЎЁдёҠе»әз«ӢдёүеҖӢзҙўеј•пјҡ`idx_ai_usage_user` (еҹәж–ј `user_id`, `called_at` йҷҚеәҸ), `idx_ai_usage_feature` (еҹәж–ј `feature`, `called_at` йҷҚеәҸ), д»ҘеҸҠ `idx_ai_usage_provider` (еҹәж–ј `provider`, `called_at` йҷҚеәҸ)гҖӮ', 'Three indexes are created on the `ai_usage_log` table: `idx_ai_usage_user` (on `user_id`, `called_at` DESC), `idx_ai_usage_feature` (on `feature`, `called_at` DESC), and `idx_ai_usage_provider` (on `provider`, `called_at` DESC).', '{ai,иӘӘжҳҺ}', 'public', 'system', '2026-04-24 11:25:40.908853+00', NULL, '7a1280b6e7a2bff93fc5743846592250a33fd7b5f18dc420af70ec1fee8983b6', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_7e74197c', '1.0', 'ws_spec0001', 'AI Provider `embed` ж–№жі•з°ҪеҗҚ', 'AI Provider `embed` Method Signature', 'factual', 'markdown', '`embed` ж–№жі•жҺҘеҸ— API йҮ‘й‘°гҖҒжЁЎеһӢеҗҚзЁұе’Ңж–Үжң¬еӯ—дёІпјҢдёҰиҝ”еӣһеҢ…еҗ«жө®й»һж•ёеҲ—иЎЁпјҲеөҢе…Ҙеҗ‘йҮҸпјүе’ҢжүҖз”Ё token ж•ёйҮҸзҡ„е…ғзө„гҖӮ', 'The `embed` method takes an API key, model name, and text string, returning a tuple containing a list of floats (the embedding vector) and the number of tokens used.', '{ai,embedding,api,method-signature}', 'public', 'system', '2026-04-24 11:31:27.640059+00', NULL, '8ca7e05bc01d9b03cc82dfdd508527e481f07deb3644e4b1dbdbb685d9ebe61e', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_c9bd6c49', '1.0', 'ws_spec0001', 'memory_nodes иЎЁдёӯзҡ„ `conflict_status` ж¬„дҪҚ', '`conflict_status` Column in `memory_nodes` Table', 'factual', 'markdown', '`memory_nodes` иЎЁеҢ…еҗ«дёҖеҖӢеҗҚзӮә `conflict_status` зҡ„ж–Үжң¬ж¬„дҪҚпјҢе…¶еҖјеҸҜд»ҘзӮә `NULL`, `''flagged''`, жҲ– `''resolved''`гҖӮ', 'The `memory_nodes` table includes a text column named `conflict_status`, which can have values of `NULL`, `''flagged''`, or `''resolved''`.', '{database_schema,conflict_management}', 'public', 'system', '2026-04-24 11:31:27.706468+00', NULL, '155f94b0cc3c745f38e13c0f4213965a92517eca84f2b2f56cb27d1c3765b21d', 'ai', NULL, NULL, NULL, NULL, 0.593, 0.800, 1.000, 0.010, 0.500, 0, 0, 0, 1, 1, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_27e2935e', '1.0', 'ws_spec0001', 'е·ҘдҪңеҚҖи§’иүІиҲҮж¬Ҡйҷҗ', 'Workspace Roles & Permissions', 'factual', 'markdown', 'е·ҘдҪңеҚҖе…§зҡ„зҹҘиӯҳеӯҳеҸ–еҡҙж јеҹәж–ји§’иүІпјҢзү№еҲҘжҳҜе°Қж–јгҖҢжңүжўқд»¶е…¬й–ӢгҖҚ(conditional_public) е’ҢгҖҢеҸ—йҷҗгҖҚ(restricted) зҡ„е·ҘдҪңеҚҖгҖӮ', 'Access to knowledge within a workspace is strictly role-based, especially for `conditional_public` and `restricted` workspaces.', '{access-control,roles,permissions}', 'public', 'system', '2026-04-24 11:25:39.701124+00', NULL, 'd1a47e7c44150c33817a30ae6a42bfaf25f2225950b5aff7824c979513ec19be', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_playbook_002', '1.0', 'ws_spec0001', 'е·ҘдҪңжөҒзЁӢпјҡдәәж©ҹеҚ”дҪңеҜ©ж ёйҖұжңҹ', 'Workflow: Human-in-the-Loop Review Cycle', 'procedural', 'markdown', '### еҚ”дҪңжөҒзЁӢ
1. **AI жҸҗжЎҲ**пјҡAI еңЁе°Қи©ұжҲ–ж”қе…ҘйҒҺзЁӢдёӯз”ҹжҲҗе»әиӯ°зҜҖй»һпјҢдёҰйҖІе…Ҙ review_queueгҖӮ
2. **дәәе·ҘеҜ©ж ё**пјҡдҪҝз”ЁиҖ…е®ҡжңҹжӘўжҹҘйҡҠеҲ—д»Ҙе®Ңе–„гҖҒеҗҲдҪөжҲ–жӢ’зө•жҸҗжЎҲгҖӮ
3. **жҸҗдәӨ**пјҡжү№еҮҶзҡ„зҹҘиӯҳжҲҗзӮәж°ёд№… Evergreen ең–иӯңзҡ„дёҖйғЁеҲҶгҖӮ', '### Collaboration Workflow
1. **AI Proposal**: AI generates suggested nodes during chat or ingestion, which enter the review_queue.
2. **Human Review**: Users periodically check the queue to refine, merge, or reject proposals.
3. **Commit**: Approved knowledge becomes part of the permanent Evergreen graph.', '{workflow,review,collaboration}', 'public', 'system', '2026-04-24 13:35:31.814382+00', NULL, 'manual_playbook_002', 'ai', NULL, NULL, NULL, NULL, 0.503, 0.500, 1.000, 0.010, 0.500, 0, 0, 0, 1, 1, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_2a909fec', '1.0', 'ws_spec0001', 'create_node й©—ж”¶жғ…еўғпјҡеғ…еЎ«еҜ« title_en', 'create_node Acceptance Scenario: title_en Only', 'factual', 'markdown', 'й©—ж”¶жғ…еўғд№ӢдёҖжҳҜжё¬и©Ұ `create_node` еҮҪж•ёеңЁеҸӘеЎ«еҜ« `title_en` иҖҢдёҚеЎ«еҜ« `title_zh` зҡ„жғ…жіҒдёӢпјҢжҳҜеҗҰиғҪжӯЈеёёе»әз«ӢзҜҖй»һпјҢдё” `title_zh` й җиЁӯзӮәз©әеӯ—дёІгҖӮ', 'One acceptance scenario is to test if the `create_node` function can successfully create a node when only `title_en` is provided and `title_zh` is left empty, with `title_zh` defaulting to an empty string.', '{й©—ж”¶жғ…еўғ,зҜҖй»һе»әз«Ӣ,api,жё¬и©Ұ}', 'public', 'system', '2026-04-25 02:39:27.638354+00', NULL, 'ad2e98d78ac8c1440456beee48b50a220b21705bd120a7fbdb0c32c8d6ca88fa', 'ai', NULL, NULL, NULL, NULL, 0.593, 0.800, 1.000, 0.010, 0.500, 0, 0, 0, 1, 1, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_c24bbdad', '1.0', 'ws_spec0001', 'AI д»ЈзҗҶе»әз«ӢзҜҖй»һжҷӮеҝ…й ҲжҢҮе®ҡ source_type зӮә "ai"', 'AI Agents Must Specify source_type as "ai" When Creating Nodes', 'factual', 'markdown', 'з•¶ AI д»ЈзҗҶе»әз«ӢзҹҘиӯҳзҜҖй»һжҷӮпјҢ`source_type` ж¬„дҪҚеҝ…й ҲжҳҺзўәиЁӯе®ҡзӮә `"ai"`гҖӮйҖҷжңғе°ҺиҮҙиіҮж–ҷеә«дёӯзҡ„ `source_type` ж¬„дҪҚзӮә ''ai''пјҢдё”еҜ©ж ёдҪҮеҲ—дёӯзҡ„ `proposer_type` ж¬„дҪҚд№ҹзӮә ''ai''гҖӮ', 'When an AI agent creates a knowledge node, the `source_type` field must be explicitly set to `"ai"`. This results in the `source_type` field in the database being ''ai'' and the `proposer_type` field in the review queue also being ''ai''.', '{aiд»ЈзҗҶ,зҜҖй»һе»әз«Ӣ,api,иҰҸзҜ„}', 'public', 'system', '2026-04-25 02:39:26.969779+00', NULL, '59ac0bfa279bf73aaa1a12d438248fbd2ddec10e108d722f3e09e55b42d105dd', 'ai', NULL, NULL, NULL, NULL, 0.593, 0.800, 1.000, 0.010, 0.500, 0, 0, 0, 1, 1, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_4b0125e0', '1.0', 'ws_spec0001', 'ж”қе…ҘзҜҖй»һзҡ„дҫҶжәҗж–Үд»¶дҝқз•ҷзӯ–з•Ҙ', '?оіҮ?иқӯВҖжҡәоөҘ?йқҪоіү??оёҒ?з‘ј?Source File Retention on Ingested Nodes', 'factual', 'markdown', 'з•¶ж–Үд»¶иў«ж”қе…ҘжҷӮпјҢе…¶еҺҹе§ӢдҫҶжәҗж–Үд»¶жңғиў«дҝқз•ҷзӮәдёҖеҖӢзү№ж®ҠзҜҖй»һпјҢд»ҘзўәдҝқиҗғеҸ–зҡ„еҸҜжәҜжҖ§пјҢдёҰжҸҗдҫӣеҫһд»»дҪ•иҗғеҸ–зҜҖй»һеӣһеҲ°е…¶дҫҶжәҗж®өиҗҪзҡ„зӣҙжҺҘйҖЈзөҗпјҢиҖҢдёҚжұЎжҹ“дё»зҹҘиӯҳең–иӯңгҖӮ', '?е—Ҷ?йҡһе—үв—Ө?оіҮ??оҝў??оёҒ??оёҒ?з‘јоқғ?йӣҝо°¬оҫӯйҠқВҖ?п•ҹпҸ·з•ҫп“Ӯ?жҡәоө§в—ӨйқҪоіү?еҡ—п—№иӘ‘иқЈз®”??о“Һ??п„’оҸ»йӨҲиіЈж»І?ж”№?йҠқиЎҢ?йқҳо®Қ?йҡһйўұ??о“Һ?иқӯВҖжҡәоөӨпҚ‘?е—Ҷ?з•ҫиҸ”о’Ұ?п„”оӯң?д»ҝВҖ??еҡ—п—ҪВҖп—№??пҒ¶??оҡӨиң“?дәҘ??оЎҝ???When a document is ingested, its original source file is retained as a special node to ensure extraction traceability and provide a direct link from any extracted node back to its source passage without polluting the main knowledge graph.', '{еӯҳеҸ–,дҫҶжәҗ,ж–Үд»¶}', 'public', 'system', '2026-04-24 11:25:40.736854+00', NULL, '944b98fa9abb8ad8331129296039305a02c7b9291c5257066ca17a2918a88b3a', 'ai', NULL, NULL, NULL, NULL, 0.593, 0.800, 1.000, 0.010, 0.500, 0, 0, 0, 1, 1, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_82b732f5', '1.0', 'ws_spec0001', 'е…§е®№ж јејҸж¬„дҪҚ (`content.format`)', 'Content Format Field (`content.format`)', 'factual', 'markdown', '`content.format` ж¬„дҪҚжҳҜдёҖеҖӢеҝ…еЎ«еӯ—дёІпјҢжҺҘеҸ—еҖј `"plain"` жҲ– `"markdown"`пјҢй җиЁӯзӮә `"plain"`гҖӮ', 'The `content.format` field is a required string, accepting values `"plain"` or `"markdown"`, and defaults to `"plain"`.', '{schema,ж јејҸ,е…§е®№}', 'public', 'system', '2026-04-24 11:25:39.870431+00', NULL, 'c804559e5fa18383474f35358a7146e7a9493a0cbf66038ca86a8e45800a35c4', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_ee62ef2c', '1.0', 'ws_spec0001', 'з°ЎеҢ–ең–иӯңијүиҚ·зҡ„ API з«Ҝй»һ', 'API Endpoint for Stripped Graph Payload', 'factual', 'markdown', 'з«Ҝй»һ `GET /api/v1/workspaces/{ws_id}/graph?preview=true` з”Ёж–јжҸҗдҫӣз°ЎеҢ–ең–иӯңијүиҚ·гҖӮ', 'The endpoint `GET /api/v1/workspaces/{ws_id}/graph?preview=true` serves the stripped graph payload.', '{api,з«Ҝй»һ,з°ЎеҢ–зөҗж§Ӣ}', 'public', 'system', '2026-04-24 11:25:39.793666+00', NULL, '692f0b08e25bd54aa1bb741d90fa13d17d3c521fb8eae5d5eea3f70315d0124c', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_2e101ff1', '1.0', 'ws_spec0001', 'AI дҪҝз”Ёж—ҘиӘҢиЎЁзөҗж§Ӣ', 'AI Usage Log Table Schema', 'factual', 'markdown', 'е»әз«Ӣж–°зҡ„ `ai_usage_log` иЎЁпјҢеҢ…еҗ« `id`, `user_id`, `key_source`, `provider`, `model`, `feature`, `workspace_id`, `node_id`, `tokens_input`, `tokens_output`, `tokens_total`, `latency_ms`, `success`, `error_code`, `called_at` зӯүж¬„дҪҚгҖӮ', 'A new `ai_usage_log` table is created with fields such as `id`, `user_id`, `key_source`, `provider`, `model`, `feature`, `workspace_id`, `node_id`, `tokens_input`, `tokens_output`, `tokens_total`, `latency_ms`, `success`, `error_code`, and `called_at`.', '{ai,иӘӘжҳҺ}', 'public', 'system', '2026-04-24 11:25:40.887123+00', NULL, 'aca74ab39cb65f069516c41944edd02ff6232f8dea53e0413c1c026bad64746c', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_73ea8135', '1.0', 'ws_spec0001', 'з°ЎеҢ–ең–иӯңијүиҚ·зөҗж§Ӣ', 'Stripped Graph Payload Structure', 'factual', 'markdown', 'з°ЎеҢ–ең–иӯңијүиҚ·еҢ…еҗ« `preview_mode: true` д»ҘеҸҠз°ЎеҢ–еҫҢзҡ„ `nodes` е’Ң `edges` ж•ёзө„гҖӮзҜҖй»һеғ…еҢ…еҗ« `id` е’Ң `position`пјҢиҖҢйӮҠеҢ…еҗ« `from`, `to`, е’Ң `relation`гҖӮ', 'The stripped graph payload includes `preview_mode: true` and stripped `nodes` and `edges` arrays. Nodes only contain `id` and `position`, while edges contain `from`, `to`, and `relation`.', '{APIе„ӘеҢ–,з°ЎеҢ–зөҗж§Ӣ,apiе„ӘеҢ–,зөҗж§Ӣ,ијүиҚ·}', 'public', 'system', '2026-04-24 11:25:39.742298+00', NULL, 'cda26ec974454fdbdab284c8fb6a214080176621f450398f2a91a6605e980ddf', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_8575b4a1', '1.0', 'ws_spec0001', 'е°ҒеӯҳзҜҖй»һеңЁй җиЁӯиҰ–ең–иҲҮжҗңе°Ӣдёӯйҡұи—Ҹ', 'Archived Nodes Hidden in Default View and Search', 'factual', 'markdown', 'е°ҒеӯҳзҜҖй»һдёҚжңғйЎҜзӨәеңЁй җиЁӯзҡ„ең–иӯңиҰ–ең–дёӯпјҢдё”жңғеҫһжҗңе°ӢзөҗжһңдёӯжҺ’йҷӨгҖӮ', 'з”Үиұў?иқӯВҖжҡәоөЈ??пҒөпҠҫ?жӣүоҜӯ?о“‘иә«?п„’?з‘јпјә??п—»?ж’ п•ҹ??о°©и‘ү??Archived nodes are not displayed in the default Graph View and are excluded from search results.', '{иҰ–ең–,йҡұи—Ҹ,е°Ғеӯҳ}', 'public', 'system', '2026-04-24 11:25:39.518038+00', NULL, '0d0565328c95ff76b4d7bddc886b99868a2cef6b224c8263f7cfb5763f7e465f', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_c4ce77e1', '1.0', 'ws_spec0001', 'е°ҒеӯҳзҜҖй»һеңЁе°Ҳеұ¬зҡ„гҖҢе°ҒеӯҳгҖҚиҰ–ең–дёӯеҸҜиҰӢ', 'Archived Nodes Visible in Dedicated "Archive" View', 'factual', 'markdown', 'е°ҒеӯҳзҜҖй»һеҸҜд»ҘеңЁе°Ҳз”Ёзҡ„гҖҢе°ҒеӯҳгҖҚиҰ–ең–дёӯиЁӘе•Ҹе’ҢйЎҜзӨәпјҢи©ІиҰ–ең–еҸҜеҫһе·ҘдҪңеҚҖеҒҙйӮҠж¬„йҖІе…ҘгҖӮ', 'Archived nodes are accessible and displayed within a dedicated "Archive" view, which can be reached from the workspace sidebar.', '{иҰ–ең–,е°Ғеӯҳ,йҡұи—Ҹ}', 'public', 'system', '2026-04-24 11:25:39.57505+00', NULL, 'bf861774dffed73c434ea5c3c5a0d846a0ac249c2558d9ad2e8b12173dcaa5e2', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_aab6d931', '1.0', 'ws_spec0001', 'з°ЎеҢ–ең–иӯңијүиҚ·зҡ„еҝ«еҸ–ж”ҝзӯ–', 'Caching Policy for Stripped Graph Payload', 'factual', 'markdown', 'й җиҰҪијүиҚ·дёҚеҸҜз”ұе®ўжҲ¶з«Ҝеҝ«еҸ–пјҢйҖҷз”ұйҹҝжҮүжЁҷй ӯ `Cache-Control: no-store` жҢҮзӨәгҖӮ', 'The preview payload is not cacheable by the client, indicated by the response header `Cache-Control: no-store`.', '{еҝ«еҸ–,APIе„ӘеҢ–,жҖ§иғҪ}', 'public', 'system', '2026-04-24 11:25:39.829461+00', NULL, '6e6398e27fe86238ff08625e26c0b131b6cabffda49bd17964086ec5d8f0d341', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_80054468', '1.0', 'ws_spec0001', 'з°ЎеҢ–ең–иӯңијүиҚ·дёӯзңҒз•Ҙзҡ„ж¬„дҪҚ', 'Omitted Fields in Stripped Graph Payload', 'factual', 'markdown', 'з°ЎеҢ–ең–иӯңијүиҚ·йҹҝжҮүдёӯе®Ңе…ЁзңҒз•Ҙзҡ„ж¬„дҪҚеҢ…жӢ¬ `title_zh`, `title_en`, `body_zh`, `body_en`, `tags`, `author`, `signature`, `trust_score` д»ҘеҸҠжүҖжңүдҫҶжәҗ (provenance) ж¬„дҪҚгҖӮ', 'Fields entirely omitted from the stripped graph payload response include `title_zh`, `title_en`, `body_zh`, `body_en`, `tags`, `author`, `signature`, `trust_score`, and all provenance fields.', '{иіҮж–ҷијүиҚ·,APIе„ӘеҢ–,з°ЎеҢ–зөҗж§Ӣ}', 'public', 'system', '2026-04-24 11:25:39.775592+00', NULL, 'b6201a17eb809238e3e05fdce0623986c75613178b63db97cecd1176547cd3ec', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_53258df1', '1.0', 'ws_spec0001', 'JWT Token з”ҹе‘ҪйҖұжңҹ', 'JWT Token Lifetime', 'factual', 'markdown', 'JWT Token?п„”??иіЎВҖжңӣ???жҶӯжҠјВҖоҝҳжҒҘ?е—Ҙеһў?пҗЈоҜӯToken?оҺ•??пҡ–иқҷ?зҒј/auth/refresh`иқЎиҲ«??и„°??пҡҳоЎҮ?жёЎ???The JWT Token lifetime is 7 days. Clients should refresh the token before expiry using the `/auth/refresh` endpoint.', 'JWT Token?п„”??иіЎВҖжңӣ???жҶӯжҠјВҖоҝҳжҒҘ?е—Ҙеһў?пҗЈоҜӯToken?оҺ•??пҡ–иқҷ?зҒј/auth/refresh`иқЎиҲ«??и„°??пҡҳоЎҮ?жёЎ???The JWT Token lifetime is 7 days. Clients should refresh the token before expiry using the `/auth/refresh` endpoint.', '{jwt,token,з”ҹе‘ҪйҖұжңҹ,йҮҚж–°ж•ҙзҗҶ}', 'public', 'system', '2026-04-24 11:25:40.146846+00', NULL, '8399bf427db47ef13542102eafca9d11e86950d69a8ad492ce82ba7fd62fe25e', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_ef3bebe9', '1.0', 'ws_spec0001', 'JWT Token ијүиҚ·зөҗж§Ӣ', 'JWT Token Payload Structure', 'factual', 'markdown', 'JWT Token ијүиҚ·еҢ…жӢ¬ `sub` (дҪҝз”ЁиҖ… ID)гҖҒ`email`гҖҒ`display_name`гҖҒ`iat` (з°ҪзҷјжҷӮй–“) е’Ң `exp` (йҒҺжңҹжҷӮй–“) зӯүж¬„дҪҚгҖӮ', 'The JWT Token payload includes `sub` (user ID), `email`, `display_name`, `iat` (issued-at time), and `exp` (expiry time) fields.', '{jwt,token,ијүиҚ·,е°Қи«Үз®ЎзҗҶ}', 'public', 'system', '2026-04-24 11:25:40.127115+00', NULL, '28b7156405594bd26902d892ca1e916dbbde4c482b49dbb04839f3fec346da9a', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_f9a2bb47', '1.0', 'ws_spec0001', 'дҫҶжәҗж–Үд»¶зҜҖй»һж¬„дҪҚе®ҡзҫ©', 'Source Document Node Field Definition', 'factual', 'markdown', 'дҫҶжәҗж–Үд»¶зҜҖй»һеҢ…еҗ«д»ҘдёӢж¬„дҪҚпјҡ`content_type` зӮә `source_document`пјҢ`title_zh`/`title_en` зӮәеҺҹе§ӢжӘ”еҗҚ + еҢҜе…ҘжҷӮй–“жҲіпјҢ`body_zh`/`body_en` зӮәе®Ңж•ҙзҡ„жҸҗеҸ–ж–Үжң¬жҲ–иҪүйҢ„зЁҝпјҢ`visibility` й җиЁӯзӮә `private`пјҢдё” `source_type` зӮә `human`гҖӮ', 'A source document node has the following fields: `content_type` as `source_document`, `title_zh`/`title_en` as original filename + ingestion timestamp, `body_zh`/`body_en` as full extracted text or transcript, `visibility` defaulting to `private`, and `source_type` as `human`.', '{еҫҢз«ҜиіҮж–ҷ,дҫҶжәҗ,ж–Үд»¶}', 'public', 'system', '2026-04-24 11:25:40.77386+00', NULL, '7d2711cfebac275319bf5ebc62579cd1b3de62a9d03f2952bdd65e03bb984b84', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
