INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_5e292da7', '1.0', 'ws_spec0001', 'дҫҶжәҗж јејҸеҸғиҖғзҜ„жң¬', 'зҡһо“Ҹо№өж’ҳоҗұ??еҶҪо№өж’ҳ?Source Format Reference Formats', 'factual', 'markdown', 'дёҚеҗҢзҡ„дҫҶжәҗж јејҸдҪҝз”Ёзү№е®ҡзҡ„еҸғиҖғж јејҸпјҡMarkdown/зҙ”ж–Үеӯ—дҪҝз”Ё В§<heading> жҲ– В¶<paragraph_index>пјӣPDF/DOCX дҪҝз”Ё page:<n>, para:<m>пјӣPPTX дҪҝз”Ё slide:<n>пјӣеҪұзүҮ/йҹіиЁҠдҪҝз”Ё <HH:MM:SS>-<HH:MM:SS>пјӣз¶Ій ҒдҪҝз”Ё <section heading or XPath fragment>гҖӮ', 'йҠқпҡ—??п„“??жҫҶ??пҗҘпҸ·ж‘°о«І?ж’ҳоҹЎоң…?жҫҶ?еҡ—о©әarkdown/иққоқғ?ж‘®оӨҳиқҷ??`зҰ®<heading>` ??`з№һ<paragraph_index>`еҡ—о¬ҡDF/DOCX йӣҝиј»оң… `page:<n>, para:<m>`еҡ—о¬ҡPTX йӣҝиј»оң… `slide:<n>`еҡ—о®Қи”Ј???е”ҫ?йӣҝиј»оң… `<HH:MM:SS>-<HH:MM:SS>`еҡ—о®ҸйӣҜ?ојәиқҷ??`<section heading or XPath fragment>`??Different source formats use specific reference formats: Markdown/plain text uses `зҰ®<heading>` or `з№һ<paragraph_index>`; PDF/DOCX uses `page:<n>, para:<m>`; PPTX uses `slide:<n>`; Video/audio uses `<HH:MM:SS>-<HH:MM:SS>`; and Web pages use `<section heading or XPath fragment>`.', '{}', 'public', 'system', '2026-04-24 11:25:40.812338+00', NULL, '588186fe569c2ea8746c1b3951552737e78c888f03e512bb9c31ce683af3aa0f', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
