INSERT INTO public.memory_nodes (id, schema_version, workspace_id, title_zh, title_en, content_type, content_format, body_zh, body_en, tags, visibility, author, created_at, updated_at, signature, source_type, source_document, extraction_model, copied_from_node, copied_from_ws, trust_score, dim_accuracy, dim_freshness, dim_utility, dim_author_rep, votes_up, votes_down, verifications, traversal_count, unique_traverser_count, status, archived_at, embedding, validity_confirmed_at, validity_confirmed_by, source_file) VALUES ('mem_964c73a3', '1.0', 'ws_spec0001', 'MEMTRACE_TOKEN еҢҝеҗҚиЎҢзӮә', 'MEMTRACE_TOKEN Anonymous Behavior', 'factual', 'markdown', 'иӢҘжңӘеӮійҒһ `MEMTRACE_TOKEN`пјҢзі»зөұе°Үз¶ӯжҢҒеҢҝеҗҚиЎҢзӮәпјҢеғ…иғҪеӯҳеҸ–е…¬й–Ӣе·ҘдҪңеҚҖпјҢ`list_workspaces` е°Үиҝ”еӣһе…¬й–Ӣеә«жҲ–з©әеҲ—иЎЁгҖӮ', 'If `MEMTRACE_TOKEN` is not provided, the system will maintain anonymous behavior, allowing access only to public workspaces. `list_workspaces` will return public repositories or an empty list.', '{з’°еўғи®Ҡж•ё,API,иӘҚиӯү,еҢҝеҗҚеӯҳеҸ–}', 'public', 'system', '2026-04-26 00:29:47.061108+00', NULL, '12b69126a9d518c5b28e719a150430576fa04e99ea78b9b1c86d9a7769fee9eb', 'ai', NULL, NULL, NULL, NULL, 0.715, 0.800, 1.000, 0.500, 0.500, 0, 0, 0, 0, 0, 'active', NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
